INSERT INTO public.program_days (program_id, program_slug, day_number, day_title, title, estimated_minutes, cards)
VALUES (
  (SELECT id FROM public.programs WHERE slug = 'gut_health_reset' LIMIT 1),
  'gut_health_reset',
  1,
  'The First Signal',
  'Day 1 - The First Signal',
  12,
  '[{"type":"intro","dayNumber":1,"dayTitle":"The First Signal","goal":"Send the first clear signal to your gut using 5 simple steps","estimatedMinutes":12,"phase":"Phase 1 · Signals & Awareness"},{"type":"lesson","title":"Before you start","paragraphs":["This is a general wellness program, not medical treatment or a diagnosis.","If you have a diagnosed gut condition, recent abdominal surgery, a heart condition, or symptoms that concern you, consult your doctor before starting or modify the practice safely.","Do not start probiotic supplements during the program. Avoid cold drinks and avoid eating after 9 PM while following this reset."],"highlight":"Use the program as daily support, not as a replacement for medical care."},{"type":"lesson","title":"What today is about","paragraphs":["Most gut programs start by telling you what to eat differently. This one starts differently. Your gut has its own nervous system: 500 million nerve cells that respond to signals before food even arrives. Day 1 wakes up these nerve pathways with five simple steps. Nothing complicated. Nothing expensive. Everything free. You do not need to change what you eat today. Only the temperature of your drinks."]},{"type":"action_step","title":"Step 1: Cold Water Face Splash","instructions":["Go to your sink. Splash cold water on your face 5 to 7 times.","Do this before tea, before food, before your phone.","Takes 10 seconds."],"stepNumber":1,"whyThisWorks":"Cold water on the face triggers the dive reflex: your body''s ancient survival response. This immediately wakes up the vagus nerve which is the direct physical connection between your brain and your gut. When the vagus nerve fires, your gut starts moving food properly and digestive enzymes switch on.","highlight":"You may feel this in: 2 to 4 days: less bloating, more regular mornings"},{"type":"action_step","title":"Step 2: Tongue Scraping","instructions":["Before brushing your teeth, scrape your tongue from back to front 5 to 7 times.","Use a tongue scraper or the back edge of a metal spoon.","Look at what comes off: that coating is bacteria that built up overnight.","Then brush teeth normally."],"stepNumber":2,"whyThisWorks":"Your mouth and gut share the same system. Every morning without scraping, you swallow that overnight bacteria film with your first sip: and it travels straight to your gut. Removing it takes 30 seconds and directly reduces the harmful bacteria reaching your gut daily.","highlight":"You may feel this in: 3 to 4 days: morning nausea reduces, appetite feels cleaner"},{"type":"action_step","title":"Step 3: 500 ml Warm Water on Waking","instructions":["After tongue scraping, drink 500 ml of warm water slowly over 2 to 3 minutes.","Not hot. Not cold. Warm: roughly body temperature.","Important rule for today: no cold drinks for the rest of the day."],"stepNumber":3,"whyThisWorks":"Warm water triggers the gastrocolic reflex: your gut''s natural signal to empty the bowel. Cold water tightens the gut muscle and disrupts this reflex. This single step resolves morning constipation for many people within 3 to 5 days.","highlight":"You may feel this in: 3 to 5 days: more regular morning bowel movement"},{"type":"action_step","title":"Step 4: The Chewing Practice","instructions":["Choose any one meal today.","Put your phone away. Sit down.","On the first 5 bites: chew each one 20 times before swallowing.","After 5 bites, eat the rest of the meal normally.","5 bites only today: that is all."],"stepNumber":4,"whyThisWorks":"Digestion begins in the mouth. Saliva contains a digestive enzyme called amylase that starts breaking down food before it reaches the stomach. When food arrives already partially broken down, the stomach does 30% less work. Less undigested food in the lower gut means less fermentation, less gas, and less bloating.","highlight":"You may feel this in: 3 to 5 days: post-meal bloating reduces noticeably"},{"type":"action_step","title":"Step 5: Evening Humming","instructions":["In the evening: in the shower, while cooking, or sitting quietly: hum any note for 2 minutes.","Keep the sound low and steady.","Feel the vibration in your chest and throat."],"stepNumber":5,"whyThisWorks":"Humming creates vibration in the throat that directly stimulates the vagus nerve. This sends a rest-and-digest signal to the entire digestive tract. 2 minutes of humming is essentially a gentle evening massage of your gut''s nervous system.","highlight":"You may feel this in: 2 to 4 days: less gut cramping in the evenings, better sleep"},{"type":"action_step","title":"Water Schedule for Today","instructions":["On waking: 500 ml warm water before tea or food","30 minutes before breakfast: 200 ml warm water","30 minutes before lunch: 200 ml warm water","Mid-afternoon around 4 PM: 300 ml warm water or jeera water","30 minutes before dinner: 200 ml warm water","After dinner: 200 ml warm water (not during the meal)","Total target: 2.5 litres across the day","Rule: No cold water. Warm or room temperature only all day.","Rule: Only small sips during meals: not large glasses."],"stepLabel":"Water"},{"type":"action_step","title":"Today''s Gut Trick","instructions":["The fastest way to settle an upset stomach right now: splash cold water on your face, then hum for 60 seconds. The vagus nerve activation calms gut spasms faster than most antacids. Try it the next time you feel uncomfortable after a meal."],"stepLabel":"Practice 1"},{"type":"journal","prompt":"Where did I feel my gut today? Before or after meals: what did it tell me? One sentence is enough. Or just think about it before sleep.","helperText":"One sentence is enough. Notice what your gut taught you today."},{"type":"action_step","stepLabel":"Checklist","title":"Completion checklist","instructions":["Cold water face splash: done","Tongue scraping before brushing: done","500 ml warm water on waking: done","No cold drinks all day: done","Chewing practice on first 5 bites of one meal: done","Evening humming 2 minutes: done","\"Showing up honestly is the first act of healing.\""]},{"type":"close","message":"Day 1 is complete.","secondaryMessage":"You reinforced the first signal today."}]'::jsonb
)
ON CONFLICT (program_slug, day_number) DO UPDATE SET
  cards = EXCLUDED.cards,
