INSERT INTO public.program_days (program_id, program_slug, day_number, day_title, title, estimated_minutes, cards)
VALUES (
  (SELECT id FROM public.programs WHERE slug = 'gut_health_reset' LIMIT 1),
  'gut_health_reset',
  2,
  'Your Pattern Map',
  'Day 2 - Your Pattern Map',
  12,
  '[{"type":"intro","dayNumber":2,"dayTitle":"Your Pattern Map","goal":"Build the map of when, where and why your gut reacts","estimatedMinutes":12,"phase":"Phase 1 · Signals & Awareness"},{"type":"lesson","title":"What today is about","paragraphs":["You cannot improve what you cannot see. Today you build your personal gut pattern map: the exact times, places, emotions, and foods that affect your digestion. Most people experience gut discomfort as random and unpredictable. It is not. It follows very clear patterns once you start looking. The more honest and specific your map, the more useful the rest of this program becomes."]},{"type":"action_step","title":"Step 1: Full Morning Protocol","instructions":["Tongue scraping → Cold water face → 500 ml warm water","This three-step sequence is now your fixed morning gut start every day."],"stepNumber":1,"whyThisWorks":"Consistency builds the habit faster. Do it in the same order every morning.","highlight":"You may feel this in: Building from Day 1"},{"type":"action_step","title":"Step 2: Build Your Pattern Map","instructions":["Throughout today, notice and mentally note your answers to these four questions:","1. WHEN: what time of day does your gut feel worst? (morning, after lunch, evening)","2. WHAT FOOD: does discomfort follow any specific food? (dairy, wheat, oily food, raw vegetables)","3. WHAT EMOTION: what feeling was present when the gut reacted? (stress, anxiety, rushing)","4. WHAT SITUATION: after which activity? (big meal, skipping a meal, long sitting)"],"stepNumber":2,"whyThisWorks":"Patterns are information. They tell you where the gut needs support most.","highlight":"You may feel this in: 3 to 5 days: awareness of your triggers reduces anxiety about gut reactions"},{"type":"lesson","title":"Dairy is one of the most common hidden gut triggers in India","paragraphs":["As you build your pattern map today, pay specific attention to dairy.","Note whether bloating, gas or discomfort appears 30 minutes to 2 hours after: milk in chai, a glass of milk, curd, paneer, ice cream, or packaged flavoured yogurt.","If you notice a pattern with dairy: write it down clearly. This is an important signal we will work with on Days 5, 9, and 16.","You do not need to remove dairy today: just observe and note."]},{"type":"action_step","title":"Water Schedule for Today","instructions":["On waking: 500 ml warm water before tea or food","30 minutes before breakfast: 200 ml warm water","30 minutes before lunch: 200 ml warm water","Mid-afternoon around 4 PM: 300 ml warm water or jeera water","30 minutes before dinner: 200 ml warm water","After dinner: 200 ml warm water (not during the meal)","Total target: 2.5 litres across the day","Rule: No cold water. Warm or room temperature only all day.","Rule: Only small sips during meals: not large glasses."],"stepLabel":"Water"},{"type":"action_step","title":"Today''s Gut Trick","instructions":["Keep a simple note on your phone today. Every time your gut reacts: note the time and what you ate or did in the previous 2 hours. Even 3 to 4 notes from today will reveal a pattern you have never seen this clearly before."],"stepLabel":"Practice 1"},{"type":"journal","prompt":"What are my top 3 gut triggers: time, food, or emotion? One sentence is enough. Or just think about it before sleep.","helperText":"One sentence is enough. Notice what your gut taught you today."},{"type":"action_step","stepLabel":"Checklist","title":"Completion checklist","instructions":["Morning protocol (tongue scraping, cold water, warm water): done","Observed gut reactions throughout the day: done","Noted at least 3 specific triggers: done","Checked if dairy appears in the pattern: done","Chewing practice on one meal: done","Evening humming 2 minutes: done","\"Gut reactions are not random. They follow patterns: and patterns can be changed.\""]},{"type":"close","message":"Day 2 is complete.","secondaryMessage":"You reinforced your pattern map today."}]'::jsonb
)
