INSERT INTO public.program_days (program_id, program_slug, day_number, day_title, title, estimated_minutes, cards)
VALUES (
  (SELECT id FROM public.programs WHERE slug = 'gut_health_reset' LIMIT 1),
  'gut_health_reset',
  3,
  'The Temperature Reset',
  'Day 3 - The Temperature Reset',
  12,
  '[{"type":"intro","dayNumber":3,"dayTitle":"The Temperature Reset","goal":"Add the warm compress and jeera water: feel the difference after one meal","estimatedMinutes":12,"phase":"Phase 1 · Signals & Awareness"},{"type":"lesson","title":"What today is about","paragraphs":["The gut works best at body temperature. Cold drinks shock it. Warmth supports it. Today adds the warm compress: a simple clinical technique used in physiotherapy for gut problems that almost nobody knows about in daily life. Most people feel the difference within 20 minutes of the first time they try it."]},{"type":"action_step","title":"Step 1: Full Morning Protocol","instructions":["Oil pulling 5 minutes (new today: see below)","Tongue scraping → Cold water face → 500 ml warm water"],"stepNumber":1,"whyThisWorks":"Oil pulling removes harmful bacteria from the mouth before your first meal. These bacteria travel to your gut with every meal and cause gut inflammation. Removing them at the source takes 5 minutes and works within 4 to 5 days.","highlight":"You may feel this in: Full morning protocol now takes under 10 minutes"},{"type":"lesson","title":"How to do oil pulling","paragraphs":["Take 1 tablespoon of sesame oil or coconut oil. Swish it gently around your mouth for 5 minutes. Do not gargle. Do not swallow. Keep it moving between your teeth and gums slowly. After 5 minutes: spit into a bin (not the sink, oil blocks drains). Then scrape your tongue. Then rinse with warm water. Then brush teeth normally."]},{"type":"action_step","title":"Step 2: Warm Compress After Your Biggest Meal","instructions":["After your largest meal of the day, do this:","Take a small towel or cloth. Run it under warm water. Wring it out.","Lie down or sit comfortably.","Place the warm cloth on your belly: from your belly button to just below your ribs.","Leave it for 5 minutes. Breathe slowly.","The cloth should feel warm and comfortable: not hot."],"stepNumber":2,"whyThisWorks":"The digestive organs work best when blood flow to them is high. A warm compress directly increases blood flow, speeds up digestion, and removes the heavy, full feeling after eating. This technique is used in physiotherapy clinics for gut motility problems. It costs nothing and works immediately.","highlight":"You may feel this in: Immediately: post-meal heaviness reduces within 20 to 30 minutes"},{"type":"action_step","title":"Step 3: Jeera Water in the Afternoon","instructions":["Boil 1 teaspoon of cumin seeds (jeera) in 300 ml of water for 5 minutes.","Strain and drink warm.","This replaces any cold drink or packaged tea in the afternoon."],"stepNumber":3,"whyThisWorks":"Cumin directly stimulates the pancreas to release more digestive enzymes. Better enzymes mean less undigested food fermenting in the lower gut: which means less gas and less bloating.","highlight":"You may feel this in: Same day: afternoon bloating and gas reduce noticeably"},{"type":"action_step","title":"Water Schedule for Today","instructions":["On waking: 500 ml warm water before tea or food","30 minutes before breakfast: 200 ml warm water","30 minutes before lunch: 200 ml warm water","Mid-afternoon around 4 PM: 300 ml warm water or jeera water","30 minutes before dinner: 200 ml warm water","After dinner: 200 ml warm water (not during the meal)","Total target: 2.5 litres across the day","Rule: No cold water. Warm or room temperature only all day.","Rule: Only small sips during meals: not large glasses."],"stepLabel":"Water"},{"type":"action_step","title":"Today''s Gut Trick","instructions":["If you feel bloated or heavy after any meal: apply the warm compress for 5 minutes and breathe slowly. Most post-meal heaviness resolves within 20 minutes. This is more effective than walking around or drinking more water right after eating."],"stepLabel":"Practice 1"},{"type":"journal","prompt":"How did my gut feel after the warm compress? Did the post-meal heaviness change? One sentence is enough. Or just think about it before sleep.","helperText":"One sentence is enough. Notice what your gut taught you today."},{"type":"action_step","stepLabel":"Checklist","title":"Completion checklist","instructions":["Oil pulling 5 minutes: done","Morning protocol: done","Warm compress for 5 minutes after biggest meal: done","Jeera water in the afternoon: done","Extended chewing practice: 10 bites: done","Evening humming and gargling: done","\"Warmth is the language the gut understands best.\""]},{"type":"close","message":"Day 3 is complete.","secondaryMessage":"You reinforced the temperature reset today."}]'::jsonb
)
