INSERT INTO public.program_days (program_id, program_slug, day_number, day_title, title, estimated_minutes, cards)
VALUES (
  (SELECT id FROM public.programs WHERE slug = 'gut_health_reset' LIMIT 1),
  'gut_health_reset',
  4,
  'The Barefoot Walk',
  'Day 4 - The Barefoot Walk',
  12,
  '[{"type":"intro","dayNumber":4,"dayTitle":"The Barefoot Walk","goal":"First exercise day: barefoot grounding and post-meal walks begin","estimatedMinutes":12,"phase":"Phase 1 · Signals & Awareness"},{"type":"lesson","title":"What today is about","paragraphs":["Exercise enters the program today: but not in the way you expect. The gut microbiome evolved alongside constant contact with the natural world. Modern life indoors has removed most of this contact. Barefoot walking on natural ground restores something important. Post-meal walking activates the gut''s natural cleaning system."]},{"type":"action_step","title":"Step 1: Full Morning Protocol","instructions":["Oil pulling 5 min → Tongue scraping → Cold water face → 500 ml warm water","This sequence is now fixed every morning. Do it in this order."],"stepNumber":1,"whyThisWorks":"Each step prepares for the next. Oil pulling first removes bacteria, scraping collects residue, cold water fires the vagus nerve, warm water triggers the bowel reflex.","highlight":"You may feel this in: Cumulative: stronger each day"},{"type":"lesson","title":"Morning: Barefoot Grounding (10 minutes)","paragraphs":["Find any patch of natural ground: grass, soil, earth or sand.","Remove your shoes and socks.","Stand or walk slowly for 10 minutes. Morning before 9 AM is ideal.","A garden, park, or any outdoor grassy area works perfectly.","If you cannot go outside: stand on natural stone or tile floor, not carpet."],"highlight":"The earth carries a mild negative electrical charge. Skin contact allows electrons to enter the body and reduce gut inflammation markers measurably within one week. Soil microorganisms also enter through skin contact and add beneficial bacteria to your gut microbiome: something urban living has almost completely removed."},{"type":"action_step","title":"Post-Meal Walk: After Lunch and After Dinner","instructions":["Walk at a comfortable, relaxed pace for 10 to 15 minutes after each main meal.","Keep one hand lightly on your belly as you walk.","Breathe through your nose only."],"stepLabel":"Practice 1","whyThisWorks":"Walking activates the migrating motor complex: your gut''s natural cleaning wave that sweeps debris through the small intestine. This only works during gentle movement. Post-meal walking reduces blood sugar, reduces post-meal heaviness, and speeds digestion."},{"type":"action_step","title":"Step 2: Warm Compress After Biggest Meal","instructions":["5 minutes warm cloth on belly after your largest meal.","Add slow deep breathing during the compress today.","Breathe in through the nose, out through the mouth.","The breathing and the warmth together double the blood flow benefit."],"stepNumber":2,"whyThisWorks":"Diaphragmatic breathing during the warm compress physically massages the digestive organs from above with every breath.","highlight":"You may feel this in: Immediate post-meal relief building"},{"type":"action_step","title":"Water Schedule for Today","instructions":["On waking: 500 ml warm water before tea or food","30 minutes before breakfast: 200 ml warm water","30 minutes before lunch: 200 ml warm water","Mid-afternoon around 4 PM: 300 ml warm water or jeera water","30 minutes before dinner: 200 ml warm water","After dinner: 200 ml warm water (not during the meal)","Total target: 2.5 litres across the day","Rule: No cold water. Warm or room temperature only all day.","Rule: Only small sips during meals: not large glasses."],"stepLabel":"Water"},{"type":"action_step","title":"Today''s Gut Trick","instructions":["Post-meal walking also significantly lowers blood sugar after eating: especially important for people with diabetes or pre-diabetes. Even a 5-minute walk is measurably better than sitting still. The slower and more relaxed the pace, the better for digestion."],"stepLabel":"Practice 2"},{"type":"journal","prompt":"How did my gut feel on a day that included post-meal walks? Any difference from Days 1 to 3? One sentence is enough. Or just think about it before sleep.","helperText":"One sentence is enough. Notice what your gut taught you today."},{"type":"action_step","stepLabel":"Checklist","title":"Completion checklist","instructions":["Full morning protocol: done","Barefoot grounding 10 minutes on natural ground: done","Post-meal walk after lunch: done","Post-meal walk after dinner: done","Warm compress with breathing after biggest meal: done","Chewing practice: done","Evening humming and gargling: done","\"The gut remembers the earth. Give it back its memory.\""]},{"type":"close","message":"Day 4 is complete.","secondaryMessage":"You reinforced the barefoot walk today."}]'::jsonb
)
