INSERT INTO public.program_days (program_id, program_slug, day_number, day_title, title, estimated_minutes, cards)
VALUES (
  (SELECT id FROM public.programs WHERE slug = 'gut_health_reset' LIMIT 1),
  'gut_health_reset',
  5,
  'Understanding Lactose',
  'Day 5 - Understanding Lactose',
  14,
  '[{"type":"intro","dayNumber":5,"dayTitle":"Understanding Lactose","goal":"Learn what lactose intolerance is and whether it applies to you","estimatedMinutes":14,"phase":"Phase 1 · Signals & Awareness"},{"type":"lesson","title":"What today is about","paragraphs":["Today adds two new gut practices: abdominal yoga and the deep belly hum. But today also addresses one of the most overlooked causes of gut problems in India: lactose sensitivity. If dairy has been appearing in your pattern map from Day 2, today gives you the science and the practical steps to understand it."]},{"type":"lesson","title":"What is lactose intolerance: explained simply","paragraphs":["Lactose is the natural sugar found in dairy products: milk, curd, paneer, ice cream.","Lactase is the enzyme your body uses to digest lactose.","70 to 80% of South Asian adults naturally produce less lactase as they age. This is not a disease: it is a very common genetic variation in India."],"highlight":"Track dairy calmly and practically. You do not need to remove everything unless the day asks for it."},{"type":"lesson","title":"What happens when lactose is not digested","paragraphs":["Undigested lactose travels to the large intestine where gut bacteria ferment it.","This fermentation produces gas, bloating, cramping, and sometimes loose stools.","Symptoms appear 30 minutes to 2 hours after eating dairy.","The symptoms look exactly like general gut problems: which is why many people never realise dairy is the cause."],"highlight":"Track dairy calmly and practically. You do not need to remove everything unless the day asks for it."},{"type":"lesson","title":"The three levels of sensitivity","paragraphs":["Mild: can tolerate small amounts. Curd and buttermilk are usually fine.","Moderate: most liquid milk causes symptoms. Fermented dairy is usually okay.","Severe: almost all dairy causes symptoms. Even curd in large amounts."]},{"type":"lesson","title":"Good news for Indian users","paragraphs":["Traditional Indian cooking already favours fermented dairy: curd, buttermilk, chaas, lassi. These have significantly lower lactose because fermentation breaks it down.","You may not need to remove dairy entirely. You may just need to switch from liquid milk to fermented dairy."]},{"type":"lesson","title":"Pose 1: Knees to Chest (2 minutes)","paragraphs":["Lie on your back. Pull both knees to your chest. Rock gently side to side.","This directly compresses the ascending and descending colon. Gas is released."]},{"type":"lesson","title":"Pose 2: Seated Spinal Twist (1 minute each side)","paragraphs":["Sit cross-legged. Place right hand on left knee. Twist gently to the left. Hold 30 seconds. Repeat other side.","Wrings the liver, stomach, and intestines like a cloth."]},{"type":"lesson","title":"Pose 3: Child''s Pose (1 minute)","paragraphs":["Kneel, sit back on heels, fold forward, arms extended.","Gently compresses the abdominal cavity."]},{"type":"lesson","title":"Pose 4: Cat and Cow (1 minute)","paragraphs":["On hands and knees. Arch back up (cat). Drop belly down (cow). Alternate slowly 10 to 12 times."]},{"type":"lesson","title":"Pose 5: Lying Twist (30 seconds each side)","paragraphs":["Lie on back. Drop both knees to one side. Look opposite. Hold. Repeat."]},{"type":"action_step","title":"Post-Meal Walks: after lunch and after dinner","instructions":["10 to 15 minutes each at comfortable pace."],"stepLabel":"Practice 2"},{"type":"action_step","title":"Water Schedule for Today","instructions":["On waking: 500 ml warm water before tea or food","30 minutes before breakfast: 200 ml warm water","30 minutes before lunch: 200 ml warm water","Mid-afternoon around 4 PM: 300 ml warm water or jeera water","30 minutes before dinner: 200 ml warm water","After dinner: 200 ml warm water (not during the meal)","Total target: 2.5 litres across the day","Rule: No cold water. Warm or room temperature only all day.","Rule: Only small sips during meals: not large glasses."],"stepLabel":"Water"},{"type":"action_step","title":"Today''s Gut Trick","instructions":["Do the yoga sequence on an empty stomach: before breakfast or at least 2 hours after eating. This is when it works best. The poses move trapped gas and debris through the gut most effectively when the digestive system is clear."],"stepLabel":"Practice 3"},{"type":"journal","prompt":"Have I noticed any pattern with dairy in my gut reactions so far? What dairy do I eat most? One sentence is enough. Or just think about it before sleep.","helperText":"One sentence is enough. Notice what your gut taught you today."},{"type":"action_step","stepLabel":"Checklist","title":"Completion checklist","instructions":["Morning protocol: done","8-minute gut yoga sequence: done","Post-meal walks: done","Warm compress after biggest meal: done","Read the lactose section and noted whether dairy appears in my pattern: done","Chewing practice: done","Evening humming and gargling: done","\"Understanding your gut is the first step to fixing it.\""]},{"type":"close","message":"Day 5 is complete.","secondaryMessage":"You reinforced understanding lactose today."}]'::jsonb
)
