INSERT INTO public.program_days (program_id, program_slug, day_number, day_title, title, estimated_minutes, cards)
VALUES (
  (SELECT id FROM public.programs WHERE slug = 'gut_health_reset' LIMIT 1),
  'gut_health_reset',
  6,
  'The Sound Technique',
  'Day 6 - The Sound Technique',
  14,
  '[{"type":"intro","dayNumber":6,"dayTitle":"The Sound Technique","goal":"Use vibration to stimulate the gut from the inside","estimatedMinutes":14,"phase":"Phase 1 · Signals & Awareness"},{"type":"lesson","title":"What today is about","paragraphs":["Today introduces the most unexpected practice in the program: using sound vibration to stimulate the gut from the inside. Low-frequency vibration physically stimulates the smooth muscle of the digestive tract. This is the same principle used in clinical ultrasound physiotherapy for gut problems. Today you produce this vibration yourself using your own voice."]},{"type":"action_step","title":"Step 1: Deep Belly Hum: 5 Minutes","instructions":["Lie on your back or sit upright.","Place both hands flat on your belly.","Breathe in slowly through the nose.","As you breathe out: make a deep, low-pitched hum. As low as you comfortably can.","Feel the vibration under your hands on your belly.","Repeat for 5 minutes.","Lower pitch is better: you want to feel the belly vibrating, not just the chest."],"stepNumber":1,"whyThisWorks":"Low-frequency vibration in the 40 to 100 Hz range stimulates the smooth muscle of the intestines: the same mechanism used in clinical ultrasound therapy for gut motility. Many people feel a warmth or movement in the belly within 2 to 3 minutes.","highlight":"You may feel this in: Same session: warmth and movement in the belly"},{"type":"action_step","title":"Gut Yoga Sequence: 8 minutes (same as Day 5)","instructions":["Knees to chest → Seated twist → Child''s pose → Cat-cow → Lying twist"],"stepLabel":"Practice 1"},{"type":"lesson","title":"The Power Combination: Do this after your biggest meal","paragraphs":["Apply warm compress to belly for 5 minutes","While the compress is on: do the deep belly hum for 3 minutes","Warm + vibration + slow breathing together is the strongest gut motility practice in this program"]},{"type":"action_step","title":"Post-Meal Walks: after lunch and after dinner","instructions":["10 to 15 minutes each"],"stepLabel":"Practice 2"},{"type":"action_step","title":"Water Schedule for Today","instructions":["On waking: 500 ml warm water before tea or food","30 minutes before breakfast: 200 ml warm water","30 minutes before lunch: 200 ml warm water","Mid-afternoon around 4 PM: 300 ml warm water or jeera water","30 minutes before dinner: 200 ml warm water","After dinner: 200 ml warm water (not during the meal)","Total target: 2.5 litres across the day","Rule: No cold water. Warm or room temperature only all day.","Rule: Only small sips during meals: not large glasses."],"stepLabel":"Water"},{"type":"action_step","title":"Today''s Gut Trick","instructions":["The warm compress plus deep belly hum combination is the fastest way to resolve post-meal discomfort in this program. Users describe feeling the gut literally wake up within minutes. Try it after your biggest meal today and notice the difference."],"stepLabel":"Practice 3"},{"type":"journal","prompt":"Did I feel the belly vibration during the deep hum? Where exactly did I feel it? One sentence is enough. Or just think about it before sleep.","helperText":"One sentence is enough. Notice what your gut taught you today."},{"type":"action_step","stepLabel":"Checklist","title":"Completion checklist","instructions":["Morning protocol: done","Barefoot grounding: done","Gut yoga 8 minutes: done","Deep belly hum 5 minutes: done","Warm compress plus hum after biggest meal: done","Post-meal walks: done","Chewing practice: done","Evening humming and gargling: done","\"Your gut has its own voice. Today you spoke to it directly.\""]},{"type":"close","message":"Day 6 is complete.","secondaryMessage":"You reinforced the sound technique today."}]'::jsonb
)
