INSERT INTO public.program_days (program_id, program_slug, day_number, day_title, title, estimated_minutes, cards)
VALUES (
  (SELECT id FROM public.programs WHERE slug = 'gut_health_reset' LIMIT 1),
  'gut_health_reset',
  7,
  'The First Eating Window',
  'Day 7 - The First Eating Window',
  14,
  '[{"type":"intro","dayNumber":7,"dayTitle":"The First Eating Window","goal":"Start the circadian eating window and review Week 1","estimatedMinutes":14,"phase":"Phase 1 · Signals & Awareness"},{"type":"lesson","title":"What today is about","paragraphs":["Week 1 closes today. You have built five daily gut practices: vagus nerve activation, oral clearing, temperature alignment, yoga and movement, and sound vibration. Today adds the most powerful structural change in the program: the circadian eating window. This is not a diet. You eat the same foods. You just eat them within a consistent daily window."]},{"type":"action_step","title":"Step 1: The 12-Hour Eating Window Starts Today","instructions":["Note what time you eat breakfast today.","Your last food or snack must be 12 hours after breakfast.","Example: breakfast at 8 AM means last food at 8 PM.","After the window closes: only warm water, herbal tea, or jeera water.","Do not change your breakfast time. Only move the last meal earlier if needed."],"stepNumber":1,"whyThisWorks":"Gut bacteria follow a precise 24-hour clock: they are most active in the first 8 to 10 hours after your first meal. Eating outside the active window feeds bacteria when they should be resting: causing fermentation, gas, and disrupted sleep. A consistent 12-hour window stabilises the bacteria clock within 5 to 7 days.","highlight":"You may feel this in: 5 to 7 days: morning digestion improves, energy increases"},{"type":"journal","prompt":"Before bed, spend 5 minutes on these three questions:","helperText":"1. What changes have I noticed in my gut this week? 2. Which practice has had the most noticeable effect so far? 3. What dairy pattern did I notice: does dairy appear in my gut triggers?","highlight":"You may feel this in: Sets the foundation for all of Week 2"},{"type":"action_step","title":"Post-Meal Structured Walks: after lunch and after dinner","instructions":["10 to 15 minutes each, one hand resting on belly, nasal breathing"],"stepLabel":"Practice 1"},{"type":"action_step","title":"Water Schedule for Today","instructions":["On waking: 500 ml warm water with fresh grated ginger (steep 5 minutes)","30 minutes before breakfast: 200 ml plain warm water","30 minutes before lunch: 200 ml warm water","Mid-afternoon: 300 ml jeera water (boil 1 tsp cumin seeds in 300 ml water for 5 minutes)","30 minutes before dinner: 200 ml warm water","After dinner: 200 ml warm water","Before bed: 150 ml warm turmeric milk (low fat milk + turmeric + black pepper + no sugar)","Total target: 2.5 to 3 litres across the day","No cold drinks at any point today."],"stepLabel":"Water"},{"type":"action_step","title":"Today''s Gut Trick","instructions":["If hunger appears after the eating window closes: warm water with a pinch of cinnamon settles hunger signals within 10 minutes. Cinnamon also stabilises blood sugar which reduces false hunger at night."],"stepLabel":"Practice 2"},{"type":"journal","prompt":"What is the clearest change I have noticed in my gut after 7 days? What surprised me most? One sentence is enough. Or just think about it before sleep.","helperText":"One sentence is enough. Notice what your gut taught you today."},{"type":"action_step","stepLabel":"Checklist","title":"Completion checklist","instructions":["Full morning protocol: done","Barefoot grounding: done","Gut yoga 8 minutes: done","Deep belly hum 5 minutes: done","12-hour eating window started: done","Post-meal walks: done","Chewing practice: done","Week 1 reflection completed: done","Evening humming and gargling: done","\"Seven days of small signals. The gut is already listening.\""]},{"type":"close","message":"Day 7 is complete.","secondaryMessage":"You reinforced the first eating window today."}]'::jsonb
)
