INSERT INTO public.program_days (program_id, program_slug, day_number, day_title, title, estimated_minutes, cards)
VALUES (
  (SELECT id FROM public.programs WHERE slug = 'gut_health_reset' LIMIT 1),
  'gut_health_reset',
  8,
  'The Deep Breath',
  'Day 8 - The Deep Breath',
  14,
  '[{"type":"intro","dayNumber":8,"dayTitle":"The Deep Breath","goal":"Add diaphragmatic breathing as an internal gut massage","estimatedMinutes":14,"phase":"Phase 2 · Movement & Deepening"},{"type":"lesson","title":"What today is about","paragraphs":["Week 2 begins. All Week 1 practices continue. Today adds diaphragmatic breathing: belly breathing instead of chest breathing. The diaphragm is a dome-shaped muscle that sits directly above your stomach and intestines. Every deep belly breath physically massages these organs from above. Most people never use the diaphragm properly. Five minutes of belly breathing daily is one of the most effective free gut health tools available."]},{"type":"action_step","title":"Step 1: Diaphragmatic Breathing: 5 Minutes","instructions":["Lie on your back. Place one hand on your chest and one on your belly.","Breathe in slowly through the nose: only the belly hand should rise. Chest stays still.","Breathe out slowly through the mouth: belly falls. Chest stays still.","In for 4 counts. Out for 6 counts. Repeat for 5 minutes.","If your chest keeps rising: you are chest breathing. Push the air downward.","The first 2 minutes may feel unusual. By 3 to 4 minutes the belly movement feels natural."],"stepNumber":1,"whyThisWorks":"The diaphragm directly massages the stomach, liver and intestines with every breath cycle. It also supports the lower oesophageal sphincter: weak belly breathing directly causes acid reflux. 5 minutes of proper belly breathing daily is genuinely therapeutic.","highlight":"You may feel this in: Same session: tension in the upper belly reduces"},{"type":"action_step","title":"Full Morning Movement Block (do in this order)","instructions":["1. Gut yoga: 8 minutes","2. Diaphragmatic breathing: 5 minutes","3. Deep belly hum: 5 minutes","Total morning movement: approximately 18 minutes"],"stepLabel":"Movement"},{"type":"action_step","title":"Post-Meal Walks: after lunch and after dinner","instructions":["10 to 15 minutes each, nasal breathing only"],"stepLabel":"Practice 1"},{"type":"action_step","title":"Water Schedule for Today","instructions":["On waking: 500 ml warm water with fresh grated ginger (steep 5 minutes)","30 minutes before breakfast: 200 ml plain warm water","30 minutes before lunch: 200 ml warm water","Mid-afternoon: 300 ml jeera water (boil 1 tsp cumin seeds in 300 ml water for 5 minutes)","30 minutes before dinner: 200 ml warm water","After dinner: 200 ml warm water","Before bed: 150 ml warm turmeric milk (low fat milk + turmeric + black pepper + no sugar)","Total target: 2.5 to 3 litres across the day","No cold drinks at any point today."],"stepLabel":"Water"},{"type":"action_step","title":"Today''s Gut Trick","instructions":["Do 3 minutes of belly breathing before your biggest meal. Stress hormones constrict the stomach and reduce enzyme production by up to 50%. Belly breathing before eating relaxes the stomach so food is received and digested much more comfortably."],"stepLabel":"Practice 2"},{"type":"journal","prompt":"Did I feel the diaphragm moving during the breathing practice? What does tension in the upper belly tell me? One sentence is enough. Or just think about it before sleep.","helperText":"One sentence is enough. Notice what your gut taught you today."},{"type":"action_step","stepLabel":"Checklist","title":"Completion checklist","instructions":["Morning protocol with 700 ml warm water: done","Barefoot grounding: done","Gut yoga 8 minutes: done","Diaphragmatic breathing 5 minutes: done","Deep belly hum 5 minutes: done","Post-meal walks with nasal breathing: done","Warm compress after meal: done","Chewing practice: done","12-hour eating window maintained: done","\"The breath is the gut''s original rhythm. Return to it daily.\""]},{"type":"close","message":"Day 8 is complete.","secondaryMessage":"You reinforced the deep breath today."}]'::jsonb
)
