INSERT INTO public.program_days (program_id, program_slug, day_number, day_title, title, estimated_minutes, cards)
VALUES (
  (SELECT id FROM public.programs WHERE slug = 'gut_health_reset' LIMIT 1),
  'gut_health_reset',
  9,
  'The Colon Map and the Dairy Test',
  'Day 9 - The Colon Map and the Dairy Test',
  15,
  '[{"type":"intro","dayNumber":9,"dayTitle":"The Colon Map and the Dairy Test","goal":"Learn the colon massage and start the 5-day dairy elimination test","estimatedMinutes":15,"phase":"Phase 2 · Movement & Deepening"},{"type":"lesson","title":"What today is about","paragraphs":["Today introduces two important things. The colon massage: a clinical physiotherapy technique for constipation and bloating. And for those who have noted dairy in their pattern map: the 5-day dairy elimination test."]},{"type":"action_step","title":"Step 1: The Colon Massage: 5 Minutes","instructions":["Lie on your back. Use your palm or three fingers of your right hand."],"stepNumber":1},{"type":"lesson","title":"Start at the lower right side of your belly: just above the right hip bone.","paragraphs":["Move slowly upward along the right side to the bottom of your right ribs."]},{"type":"lesson","title":"Move across to the left side: below both ribs.","paragraphs":["Move slowly down the left side toward the left hip."]},{"type":"lesson","title":"Continue the stroke toward the centre and downward.","paragraphs":["Use firm but gentle circular pressure: like kneading dough lightly. Not painful.","Repeat this full circuit 5 to 6 times slowly. Total time: 5 minutes.","Best done in the morning on an empty stomach.","If any area feels tight: spend an extra 30 seconds on it gently."],"highlight":"You may feel this in: Same session for many people: bowel movement often follows within the hour"},{"type":"action_step","title":"The 5-Day Dairy Elimination Test: starts today","instructions":["If dairy appeared in your pattern map on Days 2 or 5: start this test today."],"stepLabel":"Practice 1"},{"type":"lesson","title":"What to remove for 5 days (Days 9 to 14)","paragraphs":["Remove: regular milk in all forms: in chai, as a drink, in cooking","Remove: packaged flavoured yogurt, ice cream, kheer, rabri"]},{"type":"lesson","title":"What to KEEP: these are usually fine even with lactose sensitivity","paragraphs":["Keep: homemade curd (perugu/dahi): fermentation breaks down 25 to 40% of the lactose","Keep: fresh buttermilk (chaas/majjiga): lowest lactose of all dairy","Keep: small amounts of paneer: test your personal tolerance"],"highlight":"Track dairy calmly and practically. You do not need to remove everything unless the day asks for it."},{"type":"lesson","title":"Replace milk in chai with","paragraphs":["Black tea or green tea without milk: just for these 5 days","Or use oat milk or almond milk if available"]},{"type":"lesson","title":"What to notice","paragraphs":["Does bloating reduce? Does post-meal discomfort reduce? Does gas reduce? Write down what changes.","Results become clear by Days 12 to 14."]},{"type":"action_step","title":"Full Morning Movement Block","instructions":["1. Colon massage: 5 minutes (new: do this before yoga)","2. Gut yoga: 8 minutes","3. Diaphragmatic breathing: 5 minutes","4. Deep belly hum: 5 minutes"],"stepLabel":"Movement"},{"type":"action_step","title":"Water Schedule for Today","instructions":["On waking: 500 ml warm water with fresh grated ginger (steep 5 minutes)","30 minutes before breakfast: 200 ml plain warm water","30 minutes before lunch: 200 ml warm water","Mid-afternoon: 300 ml jeera water (boil 1 tsp cumin seeds in 300 ml water for 5 minutes)","30 minutes before dinner: 200 ml warm water","After dinner: 200 ml warm water","Before bed: 150 ml warm turmeric milk (low fat milk + turmeric + black pepper + no sugar)","Total target: 2.5 to 3 litres across the day","No cold drinks at any point today."],"stepLabel":"Water"},{"type":"action_step","title":"Today''s Gut Trick","instructions":["Tight or hard areas during the colon massage show where gas or stool is trapped. Most people find the left side of the colon is significantly more tense than the right. Spend extra time on the tense areas with gentle circular pressure."],"stepLabel":"Practice 3"},{"type":"journal","prompt":"Where did I feel the colon massage most clearly? Did I start the dairy test: and what dairy did I remove? One sentence is enough. Or just think about it before sleep.","helperText":"One sentence is enough. Notice what your gut taught you today."},{"type":"action_step","stepLabel":"Checklist","title":"Completion checklist","instructions":["Morning protocol: done","Colon massage 5 minutes: done","Gut yoga 8 minutes: done","Diaphragmatic breathing 5 minutes: done","Deep belly hum 5 minutes: done","Dairy elimination test started (if applicable): done","Post-meal walks: done","Eating window maintained: done","\"When you know where your gut lives, you can speak to it directly.\""]},{"type":"close","message":"Day 9 is complete.","secondaryMessage":"You reinforced the colon map and the dairy test today."}]'::jsonb
)
