INSERT INTO public.program_days (program_id, program_slug, day_number, day_title, title, estimated_minutes, cards)
VALUES (
  (SELECT id FROM public.programs WHERE slug = 'gut_health_reset' LIMIT 1),
  'gut_health_reset',
  10,
  'The Window Narrows',
  'Day 10 - The Window Narrows',
  15,
  '[{"type":"intro","dayNumber":10,"dayTitle":"The Window Narrows","goal":"Reduce eating window to 11 hours and extend chewing practice","estimatedMinutes":15,"phase":"Phase 2 · Movement & Deepening"},{"type":"lesson","title":"What today is about","paragraphs":["Day 10 makes the first adjustment to your eating window: from 12 hours to 11. A one-hour reduction the gut bacteria clock can shift with comfortably. By Day 14 the window will be 10 hours: the optimal window for gut repair and bacterial balance."]},{"type":"action_step","title":"Step 1: Eating Window: 11 Hours Today","instructions":["Move your last meal or snack 1 hour earlier than your Day 7 window.","If you were eating until 8 PM, today stop at 7 PM.","After the window closes: warm water, jeera water or herbal tea only.","No food at all after the window closes."],"stepNumber":1,"whyThisWorks":"Each hour the eating window narrows, the overnight gut repair period extends. The gut uses the fasting time to run its natural cleaning cycle: the migrating motor complex: which sweeps debris through the small intestine. This only runs properly when no food has been eaten for at least 4 hours.","highlight":"You may feel this in: 5 to 7 days: morning energy noticeably better"},{"type":"action_step","title":"Step 2: Chewing Practice Extended to 15 Bites","instructions":["From today: 15 bites at 20 chews each for your chosen meal.","This is approximately the first third of a normal meal.","After 15 mindful bites: notice how hungry you actually still are.","Many people find they naturally eat less without trying."],"stepNumber":2,"whyThisWorks":"Extending mindful eating to the first third of the meal produces most of the satiety and digestive benefit. More chewing means better digestion and more accurate fullness signals.","highlight":"You may feel this in: Same day: fullness arrives earlier and more accurately"},{"type":"action_step","title":"Full Morning Movement Block","instructions":["1. Colon massage: 5 minutes","2. Gut yoga: 8 minutes","3. Diaphragmatic breathing: 5 minutes","4. Deep belly hum: 5 minutes"],"stepLabel":"Movement"},{"type":"action_step","title":"Evening belly breathing: new addition","instructions":["Before bed: lie on back and do 10 slow belly breaths","In for 4 counts, out for 6 counts","Takes 2 minutes and prepares the gut for overnight repair"],"stepLabel":"Practice 2"},{"type":"action_step","title":"Water Schedule for Today","instructions":["On waking: 500 ml warm water with fresh grated ginger (steep 5 minutes)","30 minutes before breakfast: 200 ml plain warm water","30 minutes before lunch: 200 ml warm water","Mid-afternoon: 300 ml jeera water (boil 1 tsp cumin seeds in 300 ml water for 5 minutes)","30 minutes before dinner: 200 ml warm water","After dinner: 200 ml warm water","Before bed: 150 ml warm turmeric milk (low fat milk + turmeric + black pepper + no sugar)","Total target: 2.5 to 3 litres across the day","No cold drinks at any point today."],"stepLabel":"Water"},{"type":"action_step","title":"Today''s Gut Trick","instructions":["If hunger appears after the eating window closes: warm water with a pinch of cinnamon settles hunger signals within 10 minutes."],"stepLabel":"Practice 3"},{"type":"journal","prompt":"How did the earlier eating cutoff feel? Did I sleep differently with a longer overnight gap? One sentence is enough. Or just think about it before sleep.","helperText":"One sentence is enough. Notice what your gut taught you today."},{"type":"action_step","stepLabel":"Checklist","title":"Completion checklist","instructions":["Morning protocol: done","Colon massage 5 minutes: done","Gut yoga 8 minutes: done","Diaphragmatic breathing 5 minutes: done","Deep belly hum 5 minutes: done","Eating window narrowed to 11 hours: done","Post-meal walks: done","Extended chewing practice 15 bites: done","Evening belly breathing before bed: done","\"Every hour the eating window narrows, the gut deepens its rest.\""]},{"type":"close","message":"Day 10 is complete.","secondaryMessage":"You reinforced the window narrows today."}]'::jsonb
)
