INSERT INTO public.program_days (program_id, program_slug, day_number, day_title, title, estimated_minutes, cards)
VALUES (
  (SELECT id FROM public.programs WHERE slug = 'gut_health_reset' LIMIT 1),
  'gut_health_reset',
  11,
  'The Vagal Depth',
  'Day 11 - The Vagal Depth',
  15,
  '[{"type":"intro","dayNumber":11,"dayTitle":"The Vagal Depth","goal":"Deepen vagus nerve activation with the cold neck press","estimatedMinutes":15,"phase":"Phase 2 · Movement & Deepening"},{"type":"lesson","title":"What today is about","paragraphs":["By Day 11 the vagus nerve is already responding to daily stimulation. Today deepens the connection with one new technique: the cold neck press: which activates the vagus nerve more directly than the face splash because the nerve exits the brain at the base of the skull."]},{"type":"action_step","title":"Step 1: Cold Neck Press: New Addition to Morning","instructions":["After the cold water face splash: take a cold damp cloth.","Press it gently to the back of your neck at the base of the skull for 20 seconds.","Done once only, immediately after the face splash.","Then continue with warm water as usual."],"stepNumber":1,"whyThisWorks":"The vagus nerve exits the brain at the base of the skull. Cold contact here produces a stronger and faster vagal response than the face reflex alone. Used clinically for acute gut spasm.","highlight":"You may feel this in: Same session: stronger morning gut activation"},{"type":"action_step","title":"Step 2: Neck Stretches After Evening Humming","instructions":["After humming and gargling in the evening: do these neck stretches for 3 minutes:","Slowly tilt your head to the left: hold 15 seconds","Slowly tilt to the right: hold 15 seconds","Slowly roll in a gentle circle: 5 times each direction","All movements slow and gentle. No forcing."],"stepNumber":2,"whyThisWorks":"The vagus nerve runs through the neck. Gentle neck movement increases vagal tone: the nerve''s ability to respond strongly. Used in physiotherapy for gut motility disorders.","highlight":"You may feel this in: Cumulative evening gut calm"},{"type":"action_step","title":"Full Morning Movement Block","instructions":["1. Colon massage: 5 minutes","2. Gut yoga: 8 minutes","3. Diaphragmatic breathing: 5 minutes","4. Deep belly hum: 5 minutes"],"stepLabel":"Movement"},{"type":"action_step","title":"Post-Meal Walks: with relaxed belly today","instructions":["Consciously relax your abdominal muscles while walking","Many people walk with a contracted abdomen: this restricts gut blood flow","Let the belly hang loose and relaxed"],"stepLabel":"Practice 1"},{"type":"lesson","title":"Evening","paragraphs":["Neck stretches 3 minutes → Humming 2 minutes → Gargling 30 seconds","Evening belly breathing 10 slow breaths before bed"]},{"type":"action_step","title":"Water Schedule for Today","instructions":["On waking: 500 ml warm water with fresh grated ginger (steep 5 minutes)","30 minutes before breakfast: 200 ml plain warm water","30 minutes before lunch: 200 ml warm water","Mid-afternoon: 300 ml jeera water (boil 1 tsp cumin seeds in 300 ml water for 5 minutes)","30 minutes before dinner: 200 ml warm water","After dinner: 200 ml warm water","Before bed: 150 ml warm turmeric milk (low fat milk + turmeric + black pepper + no sugar)","Total target: 2.5 to 3 litres across the day","No cold drinks at any point today."],"stepLabel":"Water"},{"type":"action_step","title":"Today''s Gut Trick","instructions":["The fastest way to reset a gut cramp: cold water on the face plus cold cloth on the back of the neck at the same time for 20 seconds. This combined vagus activation calms gut spasm faster than any antacid."],"stepLabel":"Practice 2"},{"type":"journal","prompt":"Can I tell the difference between a relaxed belly and a contracted one? What does relaxed digestion feel like? One sentence is enough. Or just think about it before sleep.","helperText":"One sentence is enough. Notice what your gut taught you today."},{"type":"action_step","stepLabel":"Checklist","title":"Completion checklist","instructions":["Morning protocol with cold neck press: done","Colon massage 5 minutes: done","Gut yoga 8 minutes: done","Diaphragmatic breathing 5 minutes: done","Deep belly hum 5 minutes: done","Post-meal walks with relaxed belly: done","Warm compress after meal: done","Evening neck stretches plus humming plus gargling: done","\"The vagus nerve is a highway. Every day you widen it.\""]},{"type":"close","message":"Day 11 is complete.","secondaryMessage":"You reinforced the vagal depth today."}]'::jsonb
)
