INSERT INTO public.program_days (program_id, program_slug, day_number, day_title, title, estimated_minutes, cards)
VALUES (
  (SELECT id FROM public.programs WHERE slug = 'gut_health_reset' LIMIT 1),
  'gut_health_reset',
  12,
  'The Stress and Gut Connection',
  'Day 12 - The Stress and Gut Connection',
  15,
  '[{"type":"intro","dayNumber":12,"dayTitle":"The Stress and Gut Connection","goal":"Address emotional tension stored in the gut","estimatedMinutes":15,"phase":"Phase 2 · Movement & Deepening"},{"type":"lesson","title":"What today is about","paragraphs":["The gut has more nerve cells than the spinal cord. Unprocessed stress and emotion physically store in the gut as muscular tension. Today you identify and release this tension directly. This is not about therapy or analysis. It is a simple physical practice of noticing where the gut holds tension and breathing into it."]},{"type":"action_step","title":"Step 1: Gut Tension Mapping: 5 Minutes","instructions":["Lie on your back. Close your eyes.","Slowly scan from your throat down to your lower belly.","Look for any areas that feel tight, hard, or uncomfortable.","Place one hand on each tight area for 30 seconds.","Breathe slowly: imagine the breath reaching that tight area directly.","Do not try to fix it. Just notice it and breathe.","If you feel a gurgle, a release, or a sigh: that is the gut letting go."],"stepNumber":1,"whyThisWorks":"The gut stores stress in the same way a tense muscle holds a knot. The act of consciously breathing into a tight spot triggers the parasympathetic nervous system to begin releasing that tension.","highlight":"You may feel this in: Same session: spontaneous releases are common within 5 minutes"},{"type":"action_step","title":"Full Morning Movement Block","instructions":["1. Colon massage: 5 minutes","2. Gut yoga: 8 minutes","3. Diaphragmatic breathing: 5 minutes","4. Deep belly hum: 5 minutes"],"stepLabel":"Movement"},{"type":"lesson","title":"Evening","paragraphs":["Gut tension mapping 5 minutes → Neck stretches → Humming → Gargling","Evening belly breathing before bed"]},{"type":"action_step","title":"Water Schedule for Today","instructions":["On waking: 500 ml warm water with fresh grated ginger (steep 5 minutes)","30 minutes before breakfast: 200 ml plain warm water","30 minutes before lunch: 200 ml warm water","Mid-afternoon: 300 ml jeera water (boil 1 tsp cumin seeds in 300 ml water for 5 minutes)","30 minutes before dinner: 200 ml warm water","After dinner: 200 ml warm water","Before bed: 150 ml warm turmeric milk (low fat milk + turmeric + black pepper + no sugar)","Total target: 2.5 to 3 litres across the day","No cold drinks at any point today."],"stepLabel":"Water"},{"type":"action_step","title":"Today''s Gut Trick","instructions":["If you notice your gut tightening during a stressful moment during the day: place one hand on your belly and take 5 slow belly breaths immediately. This breaks the stress-gut tension cycle before it builds into pain or bloating."],"stepLabel":"Practice 2"},{"type":"journal","prompt":"What emotion was most present in my gut today? Where in my belly did I feel it? One sentence is enough. Or just think about it before sleep.","helperText":"One sentence is enough. Notice what your gut taught you today."},{"type":"action_step","stepLabel":"Checklist","title":"Completion checklist","instructions":["Morning protocol with cold neck press: done","Colon massage 5 minutes: done","Gut yoga 8 minutes: done","Diaphragmatic breathing 5 minutes: done","Deep belly hum 5 minutes: done","Post-meal walks: done","Gut tension mapping 5 minutes: done","Eating window maintained: done","\"The gut holds what the mind has not yet processed. Give it permission to let go.\""]},{"type":"close","message":"Day 12 is complete.","secondaryMessage":"You reinforced the stress and gut connection today."}]'::jsonb
)
