INSERT INTO public.program_days (program_id, program_slug, day_number, day_title, title, estimated_minutes, cards)
VALUES (
  (SELECT id FROM public.programs WHERE slug = 'gut_health_reset' LIMIT 1),
  'gut_health_reset',
  13,
  'Consistency is the Practice',
  'Day 13 - Consistency is the Practice',
  15,
  '[{"type":"intro","dayNumber":13,"dayTitle":"Consistency is the Practice","goal":"Hold the practices through a busy or difficult day","estimatedMinutes":15,"phase":"Phase 2 · Movement & Deepening"},{"type":"lesson","title":"What today is about","paragraphs":["Day 13 is the resistance day. Life gets busy. Today you learn the minimum that maintains all gains even on the hardest days. The gut rewards consistency more than intensity. Partial completion is always better than zero."]},{"type":"action_step","title":"Step 1: Non-Negotiable Morning Core: 4 Minutes","instructions":["Even on the busiest day, these three steps cannot be skipped:","Tongue scraping: 30 seconds","Cold water on face: 10 seconds","500 ml warm water: 3 minutes to drink","Oil pulling is optional today if time is short.","Barefoot grounding: even 3 minutes outside counts."],"stepNumber":1,"whyThisWorks":"Three minutes of the core morning protocol maintains the vagal tone built over 12 days. Skipping entirely for one day sets back approximately 30% of the accumulated response.","highlight":"You may feel this in: Maintenance of all gains"},{"type":"action_step","title":"Step 2: Minimum Movement on Busy Days","instructions":["If the full movement block is not possible today:","Colon massage: 5 minutes (most important: do not skip this one)","Knees to chest yoga: 3 minutes only","Diaphragmatic breathing: 3 minutes","Total minimum: 11 minutes","If only 5 minutes available: do the colon massage only. Still worth it."],"stepNumber":2,"whyThisWorks":"The colon massage alone maintains the primary physical gut stimulus even when the full sequence is not possible.","highlight":"You may feel this in: Maintenance rather than progress: but zero regression"},{"type":"action_step","title":"Step 3: Eating Window is Non-Negotiable","instructions":["The eating window is the one rule that cannot flex even on busy days.","The gut bacteria clock does not understand \"busy\": it runs on time.","Even if everything else slips today: maintain the 11-hour window.","After the window closes: warm water only."],"stepNumber":3,"whyThisWorks":"The circadian rhythm is either consistent or disrupted. One late meal sets the bacteria clock back by 2 to 3 days.","highlight":"You may feel this in: Maintaining the clock is the highest-value action on a busy day"},{"type":"action_step","title":"Water Schedule for Today","instructions":["On waking: 500 ml warm water with fresh grated ginger (steep 5 minutes)","30 minutes before breakfast: 200 ml plain warm water","30 minutes before lunch: 200 ml warm water","Mid-afternoon: 300 ml jeera water (boil 1 tsp cumin seeds in 300 ml water for 5 minutes)","30 minutes before dinner: 200 ml warm water","After dinner: 200 ml warm water","Before bed: 150 ml warm turmeric milk (low fat milk + turmeric + black pepper + no sugar)","Total target: 2.5 to 3 litres across the day","No cold drinks at any point today."],"stepLabel":"Water"},{"type":"action_step","title":"Today''s Gut Trick","instructions":["The gut reset minimum for any day: tongue scraping + cold water face + 500 ml warm water + colon massage + eating window. These 5 things in 10 minutes maintain 70% of the program''s daily benefit. Never let a busy day mean zero."],"stepLabel":"Practice 1"},{"type":"journal","prompt":"What made today difficult and how did I adapt? What did I keep even when busy? One sentence is enough. Or just think about it before sleep.","helperText":"One sentence is enough. Notice what your gut taught you today."},{"type":"action_step","stepLabel":"Checklist","title":"Completion checklist","instructions":["Morning core minimum: done","Colon massage 5 minutes: done","Movement block minimum or full: done","Post-meal walk (even 5 minutes): done","Eating window maintained: done","Evening humming minimum 2 minutes: done","\"The gut rewards consistency more than intensity. Show up small every day.\""]},{"type":"close","message":"Day 13 is complete.","secondaryMessage":"You reinforced consistency is the practice today."}]'::jsonb
)
