INSERT INTO public.program_days (program_id, program_slug, day_number, day_title, title, estimated_minutes, cards)
VALUES (
  (SELECT id FROM public.programs WHERE slug = 'gut_health_reset' LIMIT 1),
  'gut_health_reset',
  14,
  'The Halfway Mark',
  'Day 14 - The Halfway Mark',
  15,
  '[{"type":"intro","dayNumber":14,"dayTitle":"The Halfway Mark","goal":"Review two weeks, assess the dairy test, narrow window to 10 hours","estimatedMinutes":15,"phase":"Phase 2 · Movement & Deepening"},{"type":"lesson","title":"What today is about","paragraphs":["Day 14. Halfway point. Today you measure how much has changed, assess the 5-day dairy test result, and narrow the eating window to 10 hours."]},{"type":"action_step","title":"Step 1: Eating Window: 10 Hours From Today","instructions":["Move your last meal 1 more hour earlier than Day 10.","If you were stopping at 7 PM, now stop at 6 PM.","This is the final target window for the rest of the program.","10 hours eating. 14 hours rest for the gut.","After the window closes: warm water, herbal tea or jeera water only."],"stepNumber":1,"whyThisWorks":"A 10-hour eating window with a 14-hour overnight fast gives the gut its full repair and cleaning cycle every night. Research shows this improves gut bacterial diversity by 15 to 20% within 4 weeks.","highlight":"You may feel this in: Full benefit builds over Days 14 to 21"},{"type":"action_step","title":"Dairy test assessment: 5 days completed","instructions":["You removed liquid milk from Days 9 to today. Now ask yourself honestly:"],"stepLabel":"Practice 1"},{"type":"lesson","title":"Did these symptoms reduce during the 5 days?","paragraphs":["Less bloating after meals?","Less gas in the morning or evening?","Less post-meal discomfort or cramping?","Lighter feeling after eating?"]},{"type":"lesson","title":"If YES: dairy is likely a contributor for you","paragraphs":["Today try reintroducing a small amount of milk: one cup of chai with milk.","Notice what happens in the next 2 to 3 hours.","A clear return of bloating or discomfort after reintroduction confirms the pattern."]},{"type":"lesson","title":"What this means for you going forward","paragraphs":["You do not need to remove all dairy permanently.","Switch from liquid milk to fermented dairy: curd and buttermilk are your friends.","For chai: try less milk, or switch to black tea on most days.","Keep homemade curd and fresh buttermilk: these support your gut bacteria."]},{"type":"lesson","title":"If NO difference: dairy is probably not your primary trigger","paragraphs":["Continue eating dairy as normal. Focus on the other practices.","Your gut triggers are likely stress, eating speed, or meal timing."]},{"type":"action_step","title":"Step 2: Two-Week Progress Check","instructions":["Before bed, reflect on these 5 areas: one sentence each:","1. Morning bowel movements: more regular than Day 1?","2. Post-meal bloating: reduced?","3. Evening gut cramping: less frequent?","4. Sleep quality: improved?","5. Morning energy: clearer?"],"stepNumber":2,"whyThisWorks":"Naming progress consolidates it. Users who reflect at the halfway point complete the program at 3 times the rate of those who do not.","highlight":"You may feel this in: Motivational foundation for the final week"},{"type":"action_step","title":"Full Morning Movement Block: do it slowly today","instructions":["1. Colon massage: 5 minutes","2. Gut yoga: 8 minutes","3. Diaphragmatic breathing: 5 minutes","4. Deep belly hum: 5 minutes","Notice how different each practice feels compared to Day 7"],"stepLabel":"Movement"},{"type":"action_step","title":"Water Schedule for Today","instructions":["On waking: 700 ml warm ginger water (most important drink of the day)","Fenugreek water: drain and drink the water from seeds soaked overnight","30 minutes before each meal: 200 ml warm water","Mid-afternoon: 300 ml ajwain water or jeera water","After each meal: 200 ml warm water (wait 20 minutes after eating)","Before bed: warm turmeric milk (low fat milk + turmeric + black pepper + no sugar)","Total target: 3 litres across the day","Zero cold drinks. Zero large drinks during meals: only small sips.","From today the bedtime drink changes: warm low-fat milk with turmeric + black pepper + no sugar","Turmeric is anti-inflammatory for the gut lining. Black pepper increases its absorption by 2000%","This is your gut repair drink for every night from Day 14 to Day 21"],"stepLabel":"Water"},{"type":"journal","prompt":"What is the clearest evidence my gut has changed in 14 days? What do I want to build in the final week? One sentence is enough. Or just think about it before sleep.","helperText":"One sentence is enough. Notice what your gut taught you today."},{"type":"action_step","stepLabel":"Checklist","title":"Completion checklist","instructions":["Full morning protocol: done","Colon massage 5 minutes: done","Gut yoga 8 minutes: done","Diaphragmatic breathing 5 minutes: done","Eating window narrowed to 10 hours: done","Dairy test assessed and result noted: done","Post-meal walks: done","Two-week reflection completed: done","Turmeric milk before bed: done","\"Halfway means the foundation is built. The final seven days make it permanent.\""]},{"type":"close","message":"Day 14 is complete.","secondaryMessage":"You reinforced the halfway mark today."}]'::jsonb
)
