INSERT INTO public.program_days (program_id, program_slug, day_number, day_title, title, estimated_minutes, cards)
VALUES (
  (SELECT id FROM public.programs WHERE slug = 'gut_health_reset' LIMIT 1),
  'gut_health_reset',
  15,
  'The Spice Protocol',
  'Day 15 - The Spice Protocol',
  16,
  '[{"type":"intro","dayNumber":15,"dayTitle":"The Spice Protocol","goal":"Add three healing spices as daily gut medicine","estimatedMinutes":16,"phase":"Phase 3 · Integration & Mastery"},{"type":"lesson","title":"What today is about","paragraphs":["Phase 3 begins. This week layers the most powerful traditional gut-healing practices from Indian medicine into your daily routine. Three specific spices: already in your kitchen: address gut inflammation, gut lining strength, and digestive enzyme production all at the same time. Free. Natural. Clinically backed."]},{"type":"lesson","title":"Ginger: Every Morning","paragraphs":["Add half an inch of fresh grated ginger to your morning warm water.","Steep for 5 minutes. Strain and drink.","Ginger activates digestive enzymes, reduces gut inflammation, and speeds up gastric emptying."]},{"type":"lesson","title":"Fenugreek (Methi): Overnight Soak","paragraphs":["Each night before bed: soak 1 teaspoon of fenugreek seeds in a cup of water.","In the morning: drain and drink the water before eating anything.","Fenugreek creates a protective coating on the gut lining that reduces irritation.","Also significantly lowers post-meal blood sugar."]},{"type":"lesson","title":"Turmeric: One Meal Per Day","paragraphs":["Add one quarter teaspoon of turmeric to any meal or to warm water.","Always add a pinch of black pepper when using turmeric.","Black pepper increases turmeric absorption by 2000%.","Turmeric is the most researched anti-inflammatory compound for gut health."],"highlight":"You may feel this in: 7 to 14 days of daily use: gut inflammation reduces visibly"},{"type":"action_step","title":"Full Morning Movement Block","instructions":["1. Colon massage: 5 minutes","2. Gut yoga: 8 minutes","3. Diaphragmatic breathing: 5 minutes","4. Deep belly hum: 5 minutes"],"stepLabel":"Movement"},{"type":"action_step","title":"Morning Sunlight and Barefoot Grounding: 20 minutes","instructions":["Stand or walk barefoot on grass or soil in direct morning sunlight","Before 9 AM if possible","Vitamin D from sunlight repairs the gut lining: vitamin D receptors are present throughout the intestinal wall"],"stepLabel":"Practice 1"},{"type":"action_step","title":"Post-Meal Walks: after lunch and after dinner","instructions":["10 to 15 minutes each"],"stepLabel":"Practice 2"},{"type":"action_step","title":"Managing lactose sensitivity long-term with spices","instructions":["Ginger water in the morning helps stimulate lactase enzyme production indirectly by improving overall digestive enzyme output.","Fenugreek reduces gut inflammation caused by partially undigested lactose.","Turmeric reduces the inflammatory response in the gut lining after dairy.","These three spices together make the gut more resilient to dairy: they do not cure lactose intolerance but they measurably reduce its impact."],"stepLabel":"Practice 3"},{"type":"action_step","title":"Water Schedule for Today","instructions":["On waking: 700 ml warm ginger water (most important drink of the day)","Fenugreek water: drain and drink the water from seeds soaked overnight","30 minutes before each meal: 200 ml warm water","Mid-afternoon: 300 ml ajwain water or jeera water","After each meal: 200 ml warm water (wait 20 minutes after eating)","Before bed: warm turmeric milk (low fat milk + turmeric + black pepper + no sugar)","Total target: 3 litres across the day","Zero cold drinks. Zero large drinks during meals: only small sips."],"stepLabel":"Water"},{"type":"action_step","title":"Today''s Gut Trick","instructions":["The bedtime spice drink from today: warm water with ginger + turmeric + a pinch of black pepper. Anti-inflammatory compounds delivered at night work during the gut''s overnight repair window. More effective than taking them in the morning."],"stepLabel":"Practice 4"},{"type":"journal","prompt":"Which spice did I feel most clearly in my gut today? How did the ginger water feel compared to plain warm water? One sentence is enough. Or just think about it before sleep.","helperText":"One sentence is enough. Notice what your gut taught you today."},{"type":"action_step","stepLabel":"Checklist","title":"Completion checklist","instructions":["Morning protocol: done","Ginger water on waking: done","Fenugreek seeds soaked overnight for tomorrow: done","Turmeric added to one meal with black pepper: done","Sunlight and barefoot grounding 20 minutes: done","Full morning movement block: done","Post-meal walks: done","Bedtime spice drink: done","\"The kitchen is the oldest pharmacy. The spices have always known what the gut needs.\""]},{"type":"close","message":"Day 15 is complete.","secondaryMessage":"You reinforced the spice protocol today."}]'::jsonb
)
