INSERT INTO public.program_days (program_id, program_slug, day_number, day_title, title, estimated_minutes, cards)
VALUES (
  (SELECT id FROM public.programs WHERE slug = 'gut_health_reset' LIMIT 1),
  'gut_health_reset',
  16,
  'The Fermented Revival',
  'Day 16 - The Fermented Revival',
  16,
  '[{"type":"intro","dayNumber":16,"dayTitle":"The Fermented Revival","goal":"Add one fermented food to every meal: the gut''s best friend","estimatedMinutes":16,"phase":"Phase 3 · Integration & Mastery"},{"type":"lesson","title":"What today is about","paragraphs":["Today brings the first deliberate dietary addition of the program. Not a supplement or pill. Foods your kitchen already produces that are more powerful for gut bacterial diversity than any commercial probiotic. The key word is homemade. Commercial processing kills most of the live bacteria that make fermented foods work."]},{"type":"lesson","title":"At Breakfast","paragraphs":["Plain homemade curd (perugu/dahi): not flavoured, not sweetened, not packaged."]},{"type":"lesson","title":"At Lunch","paragraphs":["Fresh buttermilk (chaas/majjiga): made at home or from a local dairy, not packaged."]},{"type":"lesson","title":"At Dinner","paragraphs":["Small bowl of plain homemade curd or rice kanji if possible."]},{"type":"action_step","title":"What genuinely counts as fermented","instructions":["Homemade curd, fresh buttermilk, idli and dosa from naturally fermented batter, rice kanji."],"stepLabel":"Practice 1"},{"type":"lesson","title":"What does NOT count","paragraphs":["Packaged flavoured yogurt, commercial buttermilk drinks, vinegar-based pickles.","These are heat-treated and contain no live bacteria."],"highlight":"You may feel this in: 5 to 7 days: gut diversity increases, digestion improves noticeably"},{"type":"action_step","title":"Fermented dairy and lactose sensitivity: the good news","instructions":["If you found you are lactose sensitive from the Days 9 to 14 test: today''s fermented foods are specifically chosen to work for you."],"stepLabel":"Practice 2","whyThisWorks":"During fermentation, bacteria break down 25 to 40% of the lactose in curd. Buttermilk (chaas) has even lower lactose than curd: most lactose-sensitive people tolerate it very well. Traditional Indian meals already favour these fermented dairy forms: your body is more suited to curd and buttermilk than to liquid milk."},{"type":"lesson","title":"If even curd causes you discomfort","paragraphs":["Start with just 2 tablespoons of curd alongside a meal: not a full bowl.","Buttermilk is usually better tolerated: try that first.","Rice kanji is completely dairy-free and excellent for the gut.","Do not worry if you cannot tolerate curd: the other practices are doing the work."]},{"type":"action_step","title":"Full Morning Movement Block","instructions":["1. Colon massage: 5 minutes","2. Gut yoga: 8 minutes","3. Diaphragmatic breathing: 5 minutes","4. Deep belly hum: 5 minutes"],"stepLabel":"Movement"},{"type":"action_step","title":"Post-Meal Walks: after lunch and after dinner","instructions":["10 to 15 minutes each"],"stepLabel":"Practice 4"},{"type":"action_step","title":"Water Schedule for Today","instructions":["On waking: 700 ml warm ginger water (most important drink of the day)","Fenugreek water: drain and drink the water from seeds soaked overnight","30 minutes before each meal: 200 ml warm water","Mid-afternoon: 300 ml ajwain water or jeera water","After each meal: 200 ml warm water (wait 20 minutes after eating)","Before bed: warm turmeric milk (low fat milk + turmeric + black pepper + no sugar)","Total target: 3 litres across the day","Zero cold drinks. Zero large drinks during meals: only small sips."],"stepLabel":"Water"},{"type":"action_step","title":"Today''s Gut Trick","instructions":["If you do not make curd at home: start today. Add 2 tablespoons of existing curd to 500 ml of warm milk. Cover and leave at room temperature overnight. It sets by morning. This is all that homemade curd requires."],"stepLabel":"Practice 5"},{"type":"journal","prompt":"How did my gut feel on a day with fermented foods at every meal? What was different? One sentence is enough. Or just think about it before sleep.","helperText":"One sentence is enough. Notice what your gut taught you today."},{"type":"action_step","stepLabel":"Checklist","title":"Completion checklist","instructions":["Morning protocol with ginger water and fenugreek water: done","Fermented food at breakfast: done","Fermented food at lunch: done","Fermented food at dinner: done","Full morning movement block: done","Sunlight and grounding 20 minutes: done","Post-meal walks: done","Bedtime spice drink: done","\"The gut is an ecosystem. Feed it what it evolved with.\""]},{"type":"close","message":"Day 16 is complete.","secondaryMessage":"You reinforced the fermented revival today."}]'::jsonb
)
