INSERT INTO public.program_days (program_id, program_slug, day_number, day_title, title, estimated_minutes, cards)
VALUES (
  (SELECT id FROM public.programs WHERE slug = 'gut_health_reset' LIMIT 1),
  'gut_health_reset',
  17,
  'Sunlight and Water',
  'Day 17 - Sunlight and Water',
  16,
  '[{"type":"intro","dayNumber":17,"dayTitle":"Sunlight and Water","goal":"Structure water intake precisely and deepen morning sunlight practice","estimatedMinutes":16,"phase":"Phase 3 · Integration & Mastery"},{"type":"lesson","title":"What today is about","paragraphs":["Two things that most people get wrong every day: when they drink water and whether they get sunlight. Dehydration is one of the most common hidden causes of poor digestion. Even mild dehydration slows gut movement, firms stool, and worsens bloating. Vitamin D from sunlight directly repairs the gut lining."]},{"type":"action_step","title":"Step 1: The Hydration Schedule: From Today","instructions":["On waking: 700 ml warm ginger water: before anything else","30 minutes before each meal: 200 ml plain warm water","Mid-afternoon: 300 ml jeera or ajwain water","After each meal: 200 ml warm water: wait 20 minutes after eating","Before bed: warm turmeric milk","During meals: only small sips: not large glasses","Total target: 2.5 to 3 litres across the day","All water warm or room temperature: zero cold water from today"],"stepNumber":1,"whyThisWorks":"Drinking large amounts of water during meals dilutes digestive enzymes and stomach acid by up to 50%. Drinking 200 ml before meals primes gastric secretion and reduces overeating. The timing of water matters as much as the quantity.","highlight":"You may feel this in: Same day: post-meal heaviness reduces, bowel movements become more regular"},{"type":"action_step","title":"Step 2: 20 Minutes Morning Sunlight","instructions":["Within 30 minutes of waking: go outside and expose face and arms to sunlight.","Direct sunlight only: not through glass.","Combine with barefoot grounding on natural ground.","20 minutes minimum. No sunglasses for the first 10 minutes.","Do not look directly at the sun."],"stepNumber":2,"whyThisWorks":"Morning sunlight does four things for gut health simultaneously: produces Vitamin D which repairs the gut lining, anchors the circadian rhythm that governs gut bacteria cycles, stimulates serotonin production (95% of serotonin is in the gut), and reduces cortisol which inflames the gut.","highlight":"You may feel this in: 7 to 10 days: gut inflammation reduces, sleep improves significantly"},{"type":"action_step","title":"Full Morning Movement Block","instructions":["1. Colon massage: 5 minutes","2. Gut yoga: 8 minutes","3. Diaphragmatic breathing: 5 minutes","4. Deep belly hum: 5 minutes"],"stepLabel":"Movement"},{"type":"action_step","title":"Sunlight and Barefoot Grounding: 20 minutes","instructions":["Do the yoga outdoors today in the sunlight if possible"],"stepLabel":"Practice 1"},{"type":"action_step","title":"Post-Meal Walks: after lunch and after dinner","instructions":["10 to 15 minutes each"],"stepLabel":"Practice 2"},{"type":"action_step","title":"Water Schedule for Today","instructions":["On waking: 700 ml warm ginger water (most important drink of the day)","Fenugreek water: drain and drink the water from seeds soaked overnight","30 minutes before each meal: 200 ml warm water","Mid-afternoon: 300 ml ajwain water or jeera water","After each meal: 200 ml warm water (wait 20 minutes after eating)","Before bed: warm turmeric milk (low fat milk + turmeric + black pepper + no sugar)","Total target: 3 litres across the day","Zero cold drinks. Zero large drinks during meals: only small sips."],"stepLabel":"Water"},{"type":"action_step","title":"Today''s Gut Trick","instructions":["Mid-afternoon gut heaviness or cramping: 200 ml warm water plus 5 minutes colon massage. Resolves most functional gut discomfort within 15 minutes. The combination of hydration and direct physical stimulation works faster than rest alone."],"stepLabel":"Practice 3"},{"type":"journal","prompt":"How did the structured water timing affect my digestion? Did pre-meal water make any difference? One sentence is enough. Or just think about it before sleep.","helperText":"One sentence is enough. Notice what your gut taught you today."},{"type":"action_step","stepLabel":"Checklist","title":"Completion checklist","instructions":["Morning protocol: done","Hydration schedule followed all day: done","20 minutes morning sunlight and grounding: done","Ginger water and fenugreek water: done","Full morning movement block: done","Fermented foods at meals: done","Post-meal walks: done","Bedtime turmeric milk: done","\"The gut and the sun have kept time together since the beginning of life.\""]},{"type":"close","message":"Day 17 is complete.","secondaryMessage":"You reinforced sunlight and water today."}]'::jsonb
)
