INSERT INTO public.program_days (program_id, program_slug, day_number, day_title, title, estimated_minutes, cards)
VALUES (
  (SELECT id FROM public.programs WHERE slug = 'gut_health_reset' LIMIT 1),
  'gut_health_reset',
  18,
  'The Evening Sequence',
  'Day 18 - The Evening Sequence',
  16,
  '[{"type":"intro","dayNumber":18,"dayTitle":"The Evening Sequence","goal":"Build the complete evening gut repair routine","estimatedMinutes":16,"phase":"Phase 3 · Integration & Mastery"},{"type":"lesson","title":"What today is about","paragraphs":["The overnight period is when the gut repairs its lining, rebalances its bacteria, and runs its cleaning cycle. What you do in the 2 hours before sleep directly determines how well this happens. Today you build a structured evening gut sequence that optimises every night from here onwards."]},{"type":"action_step","title":"The Full Evening Gut Sequence","instructions":["2 hours before sleep: Close the eating window. Last food of the day. 90 minutes before sleep: Post-dinner walk, 10 to 15 minutes, nasal breathing. 60 minutes before sleep: Bedtime spice drink: ginger + turmeric + black pepper in warm water. 45 minutes before sleep: Colon massage: 5 minutes lying on your back, gentle clockwise circuit. 30 minutes before sleep: Diaphragmatic breathing: 5 minutes, in for 4, out for","6. 15 minutes before sleep: Gut tension mapping: 3 minutes breathing into tight spots. 0: Hum 2 minutes. Gargle 30 seconds. Sleep."],"stepLabel":"Practice 1"},{"type":"action_step","title":"Full Morning Movement Block","instructions":["1. Colon massage: 5 minutes","2. Gut yoga: 8 minutes","3. Diaphragmatic breathing: 5 minutes","4. Deep belly hum: 5 minutes"],"stepLabel":"Movement"},{"type":"action_step","title":"Post-Meal Walks: after lunch and after dinner","instructions":["10 to 15 minutes each"],"stepLabel":"Practice 3"},{"type":"action_step","title":"Water Schedule for Today","instructions":["On waking: 700 ml warm ginger water (most important drink of the day)","Fenugreek water: drain and drink the water from seeds soaked overnight","30 minutes before each meal: 200 ml warm water","Mid-afternoon: 300 ml ajwain water or jeera water","After each meal: 200 ml warm water (wait 20 minutes after eating)","Before bed: warm turmeric milk (low fat milk + turmeric + black pepper + no sugar)","Total target: 3 litres across the day","Zero cold drinks. Zero large drinks during meals: only small sips."],"stepLabel":"Water"},{"type":"action_step","title":"Today''s Gut Trick","instructions":["If you cannot do the full evening sequence: the colon massage and diaphragmatic breathing together in 10 minutes produce most of the overnight gut repair benefit. These two alone are the highest-value evening steps."],"stepLabel":"Practice 5"},{"type":"journal","prompt":"How did following the full evening sequence affect my sleep and morning gut feeling? One sentence is enough. Or just think about it before sleep.","helperText":"One sentence is enough. Notice what your gut taught you today."},{"type":"action_step","stepLabel":"Checklist","title":"Completion checklist","instructions":["Morning protocol: done","Full morning movement block: done","Sunlight and grounding: done","Hydration schedule: done","Fermented foods at meals: done","Post-meal walks: done","Full evening gut sequence all steps: done","Eating window strictly maintained: done","\"The night is when the gut heals. Make the night count.\""]},{"type":"close","message":"Day 18 is complete.","secondaryMessage":"You reinforced the evening sequence today."}]'::jsonb
)
