INSERT INTO public.program_days (program_id, program_slug, day_number, day_title, title, estimated_minutes, cards)
VALUES (
  (SELECT id FROM public.programs WHERE slug = 'gut_health_reset' LIMIT 1),
  'gut_health_reset',
  19,
  'The Emotional Gut and Lactose Management',
  'Day 19 - The Emotional Gut and Lactose Management',
  16,
  '[{"type":"intro","dayNumber":19,"dayTitle":"The Emotional Gut and Lactose Management","goal":"Address the mind-gut connection and build long-term lactose management","estimatedMinutes":16,"phase":"Phase 3 · Integration & Mastery"},{"type":"lesson","title":"What today is about","paragraphs":["Two things matter today. The emotional gut: addressing stress as a physical gut disruptor. And for those with lactose sensitivity: a clear, practical, permanent management plan using Indian foods."]},{"type":"action_step","title":"Step 1: Before-Meal Breathing Practice","instructions":["Before each main meal today: sit down and take 5 slow belly breaths.","In for 4 counts. Out for 6 counts.","Let your shoulders drop. Let your belly relax.","Then eat.","Do this before every meal for the rest of the program."],"stepNumber":1,"whyThisWorks":"Stress hormones constrict the stomach and reduce enzyme production by up to 50%. Two minutes of belly breathing before eating switches the nervous system from fight-or-flight to rest-and-digest. Food eaten in a calm state is absorbed significantly better than food eaten in a hurry.","highlight":"You may feel this in: Same day: post-meal bloating reduces when meals are eaten calmly"},{"type":"lesson","title":"For chai: the most common daily dairy habit","paragraphs":["Reduce the milk in your chai gradually over 2 weeks.","Use less than you currently do: the taste adjusts quickly.","Alternatively: make chai with oat milk: available in most Indian supermarkets now.","Or switch to black tea or green tea on 3 to 4 days per week."]},{"type":"lesson","title":"For curd-based dishes: these are good for you","paragraphs":["Raita, curd rice, kadhi, lassi: all are fermented dairy and generally fine.","Most lactose-sensitive people tolerate curd and buttermilk very well.","These are better for your gut than regular milk in every way."]},{"type":"lesson","title":"For social occasions and celebrations","paragraphs":["You do not need to announce lactose sensitivity to anyone.","Simply avoid mithai, ice cream, and kheer at the end of meals.","Nobody notices and you save yourself days of discomfort."]},{"type":"lesson","title":"The lactase enzyme supplement option","paragraphs":["Lactase enzyme tablets (available at Indian pharmacies: ask for Lactaid or similar)","allow you to eat any dairy without symptoms.","Useful for weddings, festivals, and occasions where avoiding dairy is impractical.","Take one tablet just before eating dairy-heavy food."]},{"type":"lesson","title":"The most important thing to remember","paragraphs":["Lactose sensitivity is not an illness. It is information about your body.","Traditional Indian cooking already favours fermented dairy: curd, buttermilk, chaas.","You are moving toward the traditional diet your body was always better suited to."]},{"type":"action_step","title":"Full Morning Movement Block","instructions":["1. Colon massage: 5 minutes","2. Gut yoga: 8 minutes","3. Diaphragmatic breathing: 5 minutes","4. Deep belly hum: 5 minutes"],"stepLabel":"Movement"},{"type":"action_step","title":"Post-Meal Walks: after lunch and after dinner","instructions":["10 to 15 minutes each"],"stepLabel":"Practice 2"},{"type":"action_step","title":"Water Schedule for Today","instructions":["On waking: 700 ml warm ginger water (most important drink of the day)","Fenugreek water: drain and drink the water from seeds soaked overnight","30 minutes before each meal: 200 ml warm water","Mid-afternoon: 300 ml ajwain water or jeera water","After each meal: 200 ml warm water (wait 20 minutes after eating)","Before bed: warm turmeric milk (low fat milk + turmeric + black pepper + no sugar)","Total target: 3 litres across the day","Zero cold drinks. Zero large drinks during meals: only small sips."],"stepLabel":"Water"},{"type":"action_step","title":"Today''s Gut Trick","instructions":["If you notice your gut tightening during a stressful moment: place one hand on your belly and take 5 slow belly breaths immediately. This interrupts the stress-gut tension cycle before it builds into pain or bloating. Takes 60 seconds and works every time."],"stepLabel":"Practice 3"},{"type":"journal","prompt":"How did eating calmly with before-meal breathing feel compared to eating in a rush? One sentence is enough. Or just think about it before sleep.","helperText":"One sentence is enough. Notice what your gut taught you today."},{"type":"action_step","stepLabel":"Checklist","title":"Completion checklist","instructions":["Morning belly tension check: done","Full morning protocol: done","Full morning movement block: done","Sunlight and grounding: done","Before-meal breathing at every meal: done","Fermented foods at meals: done","Post-meal walks: done","Lactose management plan read and personalised: done","Evening gut sequence: done","\"The gut holds what the mind has not yet processed. Give it permission to let go.\""]},{"type":"close","message":"Day 19 is complete.","secondaryMessage":"You reinforced the emotional gut and lactose management today."}]'::jsonb
)
