INSERT INTO public.program_days (program_id, program_slug, day_number, day_title, title, estimated_minutes, cards)
VALUES (
  (SELECT id FROM public.programs WHERE slug = 'gut_health_reset' LIMIT 1),
  'gut_health_reset',
  20,
  'The Integration Day',
  'Day 20 - The Integration Day',
  16,
  '[{"type":"intro","dayNumber":20,"dayTitle":"The Integration Day","goal":"Run all practices as one natural daily rhythm","estimatedMinutes":16,"phase":"Phase 3 · Integration & Mastery"},{"type":"lesson","title":"What today is about","paragraphs":["Day 20. Tomorrow is the final day. Today is about noticing how much the practices have stopped feeling like steps and started feeling like simply how the day flows. When the practice stops feeling like effort: it has been integrated. That shift is the signal the program has worked."]},{"type":"action_step","title":"Step 1: Full Morning Ritual: Without Rushing","instructions":["Morning belly check 3 minutes → Oil pulling 5 min → Tongue scraping → Cold water face and cold neck press → 700 ml warm ginger water → Fenugreek water from overnight soak → Barefoot grounding in sunlight 20 min","Notice today how little effort this sequence requires compared to Day 1.","It should feel like brushing your teeth: automatic."],"stepNumber":1,"whyThisWorks":"When a health practice becomes automatic its benefit continues indefinitely without requiring willpower or motivation.","highlight":"You may feel this in: Fully automatic by Day 20 for most people"},{"type":"action_step","title":"Step 2: Write Your Personal Gut Protocol","instructions":["In the evening take 10 minutes and write down:","The 5 practices that made the most noticeable difference to your gut in 20 days.","The 2 to 3 practices you want to keep permanently.","Your personal lactose approach: what dairy you keep, reduce, or swap.","This becomes your personal gut maintenance plan after Day 21."],"stepNumber":2,"whyThisWorks":"People who write their personal protocol are 4 times more likely to still be following at least 3 practices 6 months later.","highlight":"You may feel this in: Preparatory for permanent change"},{"type":"action_step","title":"Full Morning Movement Block: no timer today","instructions":["1. Colon massage","2. Gut yoga","3. Diaphragmatic breathing","4. Deep belly hum","Let it take as long as it takes naturally: the body knows the sequence now"],"stepLabel":"Movement"},{"type":"action_step","title":"Evening: Full Gut Sequence","instructions":["Post-dinner walk → Spice drink → Colon massage → Belly breathing → Tension mapping → Hum → Gargle"],"stepLabel":"Practice 2"},{"type":"action_step","title":"Water Schedule for Today","instructions":["On waking: 700 ml warm ginger water (most important drink of the day)","Fenugreek water: drain and drink the water from seeds soaked overnight","30 minutes before each meal: 200 ml warm water","Mid-afternoon: 300 ml ajwain water or jeera water","After each meal: 200 ml warm water (wait 20 minutes after eating)","Before bed: warm turmeric milk (low fat milk + turmeric + black pepper + no sugar)","Total target: 3 litres across the day","Zero cold drinks. Zero large drinks during meals: only small sips.","The gut health daily minimum that maintains all gains permanently:","700 ml warm water on waking + tongue scraping + colon massage 5 minutes + 10-hour eating window + one","post-meal walk","These five habits in 10 minutes maintain a healthy gut for life"],"stepLabel":"Water"},{"type":"journal","prompt":"What has changed most about my gut in 20 days? What practice will I never stop? One sentence is enough. Or just think about it before sleep.","helperText":"One sentence is enough. Notice what your gut taught you today."},{"type":"action_step","stepLabel":"Checklist","title":"Completion checklist","instructions":["Full morning ritual without rushing: done","Full morning movement block: done","Sunlight and grounding: done","Hydration schedule: done","Before-meal breathing at every meal: done","Fermented foods at meals: done","Post-meal walks: done","Personal gut protocol written: done","Full evening gut sequence: done","\"When the practice stops feeling like a practice, it has become part of you.\""]},{"type":"close","message":"Day 20 is complete.","secondaryMessage":"You reinforced the integration day today."}]'::jsonb
)
