INSERT INTO public.program_days (program_id, program_slug, day_number, day_title, title, estimated_minutes, cards)
VALUES (
  (SELECT id FROM public.programs WHERE slug = 'gut_health_reset' LIMIT 1),
  'gut_health_reset',
  21,
  'The Anchor',
  'Day 21 - The Anchor',
  16,
  '[{"type":"intro","dayNumber":21,"dayTitle":"The Anchor","goal":"Close the program and carry the gut reset forward","estimatedMinutes":16,"phase":"Phase 3 · Integration & Mastery"},{"type":"lesson","title":"What today is about","paragraphs":["Day 21. The final day. Not an ending: a setting of the anchor. Everything built over these three weeks was designed for one purpose: to become automatic enough to need no program to maintain. Today you close with awareness, not celebration."]},{"type":"action_step","title":"Step 1: Full Morning Ritual: With Complete Attention","instructions":["Morning belly check → Oil pulling → Tongue scraping → Cold water face and neck → 700 ml warm ginger water → Fenugreek water → Barefoot grounding in sunlight","Do each step today with full attention: as if doing it for the first time.","Feel the cold water wake up your nervous system.","Feel the warm water moving through your body.","Feel your feet on the ground."],"stepNumber":1,"whyThisWorks":"Doing an automatic practice with conscious attention deepens the neural encoding and makes it significantly more durable as a lifelong habit.","highlight":"You may feel this in: Grounded. Centred. Ready."},{"type":"journal","prompt":"Before the evening gut sequence, spend 10 minutes on these five questions:","helperText":"1. What was my gut like on Day 1: how does it compare to today? 2. Which three practices made the biggest difference? 3. What is my personal lactose approach going forward? 4. Which practices do I keep permanently? 5. What surprised me most about the last 21 days?","highlight":"You may feel this in: Closure. Confidence. Clarity."},{"type":"action_step","title":"Full Morning Movement Block: held slowly and with awareness","instructions":["1. Colon massage: 5 minutes","2. Gut yoga: 8 minutes","3. Diaphragmatic breathing: 5 minutes","4. Deep belly hum: 5 minutes","This is not a routine anymore. This is care."],"stepLabel":"Movement"},{"type":"action_step","title":"Final Evening Gut Ritual","instructions":["Post-dinner walk → Spice drink → Colon massage → Belly breathing → Gut tension mapping → Hum 2 minutes → Gargle 30 seconds","Then sit for 2 minutes with hands on belly in complete stillness.","That is all."],"stepLabel":"Practice 3"},{"type":"action_step","title":"Water Schedule for Today","instructions":["On waking: 700 ml warm ginger water (most important drink of the day)","Fenugreek water: drain and drink the water from seeds soaked overnight","30 minutes before each meal: 200 ml warm water","Mid-afternoon: 300 ml ajwain water or jeera water","After each meal: 200 ml warm water (wait 20 minutes after eating)","Before bed: warm turmeric milk (low fat milk + turmeric + black pepper + no sugar)","Total target: 3 litres across the day","Zero cold drinks. Zero large drinks during meals: only small sips.","The 5 practices to keep for life: choose based on your reflection:","700 ml warm ginger water every morning: single highest-value 3-minute habit","Tongue scraping daily: 30 seconds, permanent oral-gut protection","Colon massage 5 minutes: most effective non-dietary gut intervention"],"stepLabel":"Water"},{"type":"journal","prompt":"What did 21 days of listening to my gut teach me that nothing else has? One sentence is enough. Or just think about it before sleep.","helperText":"One sentence is enough. Notice what your gut taught you today."},{"type":"action_step","stepLabel":"Checklist","title":"Completion checklist","instructions":["Full morning ritual with complete attention: done","Full morning movement block: done","Sunlight and grounding: done","Hydration schedule: done","Before-meal breathing at every meal: done","Fermented foods at all meals: done","Post-meal walks: done","Final 21-day reflection written: done","Final evening gut ritual with stillness: done","\"The gut is not broken. It was never broken. It was waiting to be heard.\""]},{"type":"lesson","title":"Quick Reference Card","paragraphs":["Keep this: return to it on hard days"]},{"type":"action_step","title":"Your morning gut ritual: every single day","instructions":["1. Belly check: 3 minutes. Lie on your back. Is the belly relaxed or tight?","2. Oil pulling: 5 minutes. Sesame or coconut oil. Spit into bin.","3. Tongue scraping: 5 to 7 strokes. Metal spoon or scraper.","4. Cold water face splash: 5 to 7 splashes. Cold neck press 20 seconds.","5. 700 ml warm ginger water: slowly, before food.","6. Fenugreek water from overnight soak: drink before eating.","7. Barefoot grounding in sunlight: 20 minutes."],"stepLabel":"Practice 4"},{"type":"action_step","title":"Daily movement block","instructions":["1. Colon massage: 5 minutes. Start lower right. Move up, across, down left.","2. Gut yoga: 8 minutes. Knees to chest, seated twist, child''s pose, cat-cow, lying twist.","3. Diaphragmatic breathing: 5 minutes. Belly rises, chest stays still.","4. Deep belly hum: 5 minutes. Low pitch. Feel the belly vibrate."],"stepLabel":"Movement"},{"type":"lesson","title":"Water: every day","paragraphs":["On waking: 700 ml warm ginger water 30 minutes before each meal: 200 ml warm water Mid-afternoon: 300 ml jeera or ajwain water After each meal: 200 ml warm water (not during) Before bed: warm turmeric milk Total: 2.5 to 3 litres. All warm or room temperature. Zero cold drinks."]},{"type":"action_step","title":"The eating window","instructions":["Week 1: 12-hour window Week 2: Narrows to 11 hours then 10 hours Week 3 onwards: 10-hour window permanently After window closes: warm water and herbal tea only. No food."],"stepLabel":"Practice 5"},{"type":"lesson","title":"The 5 permanent habits after Day 21","paragraphs":["1. 700 ml warm water every morning: the single highest-value 3-minute habit 2. Tongue scraping daily: 30 seconds, permanent oral-gut protection 3. Colon massage 5 minutes: most effective non-dietary gut tool available 4. 10-hour eating window: gut bacteria clock needs no supplements to stay healthy 5. One fermented food daily: homemade curd or buttermilk every single day"]},{"type":"lesson","title":"Lactose sensitivity quick guide","paragraphs":["Remove: liquid milk in large amounts, ice cream, packaged yogurt Keep: homemade curd, buttermilk, chaas: fermented, lower lactose Chai: reduce milk or switch to black tea on most days Social occasions: lactase enzyme tablet before dairy-heavy food \"The gut is not broken. It was never broken. It was waiting to be heard.\""],"highlight":"Track dairy calmly and practically. You do not need to remove everything unless the day asks for it."},{"type":"close","message":"Day 21 is complete.","secondaryMessage":"You reinforced the anchor today."}]'::jsonb
)
