INSERT INTO public.program_days (program_id, program_slug, day_number, day_title, title, estimated_minutes, cards)
VALUES (
  (SELECT id FROM public.programs WHERE slug = 'smoking_alcohol_quit' LIMIT 1),
  'smoking_alcohol_quit',
  1,
  'Arriving Honestly',
  'Day 1 - Arriving Honestly',
  19,
  '[{"type":"intro","dayNumber":1,"dayTitle":"Arriving Honestly","goal":"Begin with honesty about where you actually are","estimatedMinutes":19,"phase":"Phase 1 · Understand"},{"type":"lesson","title":"Safety before starting","paragraphs":["Nicotine withdrawal is uncomfortable but physically safe for most people. Alcohol withdrawal can be medically dangerous for heavy daily drinkers.","If you drink heavily every day or notice tremors, severe anxiety, sweating, confusion, or worsening symptoms, speak to a doctor or seek urgent medical help before sharply reducing.","This program supports your quit journey alongside medical care. It is not a replacement for medical care."],"highlight":"Heavy alcohol users should consult a doctor before sharply reducing."},{"type":"lesson","title":"Emergency support lines","paragraphs":["Quitline: 1800-11-2356, free and confidential.","iCall: 9152987821.","KIRAN Mental Health: 1800-599-0019."],"highlight":"Save these numbers before starting the program."},{"type":"lesson","title":"What today is about","paragraphs":["This program is designed to help you quit smoking, alcohol, or both. Not eventually. Starting now.","But Day 1 does not ask you to fight anything. It asks something harder: honesty. About where you are, why you use, and what this habit has actually been doing for you.","Most quit attempts fail not because people lack willpower but because they never understood why they started in the first place. Today is the beginning of that understanding."],"highlight":"Most quit attempts fail not because people lack willpower but because they never understood why they started in the first place. Today is the beginning of that understanding."},{"type":"audio","title":"Guided Audio","description":"Listen whenever you are ready for today’s guided reflection.","audioStoragePath":"ninety_day_transform/day-1.mp3","durationSeconds":420},{"type":"action_step","stepNumber":1,"title":"Today''s practice: The Honest Question","instructions":["Sit quietly for 2 minutes. No phone. No distraction."],"whyThisWorks":"This turns the quit from willpower into a specific repeatable response."},{"type":"lesson","title":"Ask yourself one question and let the honest answer come:","paragraphs":["\"Why do I actually smoke or drink?\"","Not the surface answer. The real one.","Is it stress? Boredom? The only time you feel calm? Habit after meals? Social anxiety? Something to do with your hands? The one thing that belongs to only you?","You do not need to write it down. Just sit with the honest answer for a moment. That honesty is the foundation everything else is built on."],"highlight":"You do not need to write it down. Just sit with the honest answer for a moment. That honesty is the foundation everything else is built on."},{"type":"lesson","title":"The science of why you use","paragraphs":["Nicotine and alcohol both trigger dopamine: the brain''s reward chemical. Over time the brain stops producing normal levels of dopamine on its own and starts depending on the substance to feel okay. This is not weakness. This is how the brain adapts to any repeated chemical input.","The urge to smoke or drink is not a character flaw. It is a trained chemical expectation. Understanding this removes shame and makes quitting a practical problem rather than a moral one."],"highlight":"The urge to smoke or drink is not a character flaw. It is a trained chemical expectation. Understanding this removes shame and makes quitting a practical problem rather than a moral one."},{"type":"journal","prompt":"What brought me here today? What do I want to be different 21 days from now?","helperText":"Write as much or as little as you want. This is private and only for you."},{"type":"close","message":"Day 1 is complete.","secondaryMessage":"Your quit is built one honest day at a time."}]'::jsonb
)
