VALUES (
  (SELECT id FROM public.programs WHERE slug = 'smoking_alcohol_quit' LIMIT 1),
  'smoking_alcohol_quit',
  6,
  'Your Indian Triggers',
  'Day 6 - Your Indian Triggers',
  19,
  '[{"type":"intro","dayNumber":6,"dayTitle":"Your Indian Triggers","goal":"The specific cultural and social triggers that make quitting harder in India","estimatedMinutes":19,"phase":"Phase 1 · Understand"},{"type":"lesson","title":"What today is about","paragraphs":["Most quit programs are written for Western users. They miss the specific social and cultural triggers that make quitting harder in India. Today you face them directly: because knowing them is how you prepare for them."]},{"type":"audio","title":"Guided Audio","description":"Listen whenever you are ready for today’s guided reflection.","audioStoragePath":"ninety_day_transform/day-6.mp3","durationSeconds":420},{"type":"lesson","title":"Smoking triggers unique to India","paragraphs":["The chai-cigarette bond: morning chai and the first cigarette are paired so tightly that one triggers the other automatically. This is one of the hardest single habits to break.","Office break culture: smoking is often the only reason to step away from a desk. The cigarette is not the need: the break is.","Post-meal smoke: immediately after lunch or dinner. Strong conditioned reflex.","Paan and cigarette combination in some communities","Stress from family expectations, financial pressure, or work culture"],"highlight":"Stress from family expectations, financial pressure, or work culture"},{"type":"lesson","title":"Drinking triggers unique to India","paragraphs":["Celebration culture: alcohol at every success, promotion, wedding, and gathering","\"I work hard, I deserve this\": drinking as the only permitted self-reward","Peer pressure that is silent but constant: the assumption that a real man drinks","Urban loneliness: moving to a new city where drinking is the social glue","Hiding from family: the secret drinking that becomes its own ritual","IPL, cricket, football: sport and alcohol linked as an unbreakable pair","Long commutes with nothing to do: the car becomes a smoking space"],"highlight":"Long commutes with nothing to do: the car becomes a smoking space"},{"type":"lesson","title":"For the chai-cigarette pairing:","paragraphs":["Keep the chai. Change what comes after it. Replace the cigarette with 3 minutes outside, a handful of saunf (fennel seeds), or 5 slow deep breaths. The brain needs to relearn that chai ends without a cigarette."]},{"type":"lesson","title":"For the office break:","paragraphs":["You still get the break. Walk to the water cooler. Step outside for 3 minutes without a cigarette. The break is what you needed: the cigarette was just the excuse to take it."]},{"type":"lesson","title":"For social drinking pressure:","paragraphs":["The most effective response is simple and honest: \"I am taking a break from drinking.\" No explanation needed. Hold a glass of lime soda. Nobody can tell the difference. The pressure to explain is in your head: most people do not notice or care."]},{"type":"action_step","stepNumber":1,"title":"Which of these Indian-specific triggers are most relevant to me? What is my plan for the hardest one?","instructions":["Choose the hardest trigger from today.","Write a one-sentence plan for how you will respond when it appears."],"whyThisWorks":"This turns the quit from willpower into a specific repeatable response."},{"type":"journal","prompt":"What did I learn from Day 6: Your Indian Triggers?","helperText":"Write one honest observation. A short answer is enough."},{"type":"close","message":"Day 6 is complete.","secondaryMessage":"Your quit is built one honest day at a time."}]'::jsonb
)
