INSERT INTO public.program_days (program_id, program_slug, day_number, day_title, title, estimated_minutes, cards)
VALUES (
  (SELECT id FROM public.programs WHERE slug = 'smoking_alcohol_quit' LIMIT 1),
  'smoking_alcohol_quit',
  7,
  'The Decision',
  'Day 7 - The Decision',
  19,
  '[{"type":"intro","dayNumber":7,"dayTitle":"The Decision","goal":"Make the private, written decision that anchors everything","estimatedMinutes":19,"phase":"Phase 1 · Understand"},{"type":"lesson","title":"What today is about","paragraphs":["Week 1 closes today. You now know your triggers, your emotional drivers, your withdrawal timeline, and the real cost of continuing. You have more self-knowledge about this habit right now than most people ever build.","Today you make The Decision. Not a dramatic public pledge. Not a promise to be perfect. A private, written, honest statement of intent. Research consistently shows that people who write their decision quit at significantly higher rates than people who only hold it in their mind."],"highlight":"Today you make The Decision. Not a dramatic public pledge. Not a promise to be perfect. A private, written, honest statement of intent. Research consistently shows that people who write their decision quit at significantly higher rates than people who only hold it in their mind."},{"type":"audio","title":"Guided Audio","description":"Listen whenever you are ready for today’s guided reflection.","audioStoragePath":"ninety_day_transform/day-7.mp3","durationSeconds":420},{"type":"journal","prompt":"What did you notice today?","helperText":"My top 3 urge triggers are:"},{"type":"action_step","stepNumber":1,"title":"Write this statement in your own words. Make it specific and honest.","instructions":["\"I am quitting [smoking / drinking / both] because _____. I know the hardest moments will be _____. I know I may slip and that does not mean I have failed. I am doing this because _____ matters more to me now.\"","Save this. You will return to it on Day 14 and Day 21.","The decision does not need to feel strong. It needs to be written.","Tell one person: just one. People with social support quit at 3 times the rate of those who quit alone.","Phase 2 begins tomorrow. It is where the actual quit tools are introduced.","You have already done the hardest intellectual work. Phase 2 is practical."],"whyThisWorks":"This turns the quit from willpower into a specific repeatable response."},{"type":"lesson","title":"Phase 2 begins tomorrow","paragraphs":["Phase 2 is where the quit becomes real. You now know your triggers and your emotional drivers. Phase 2 gives you the specific, clinically-backed tools to handle the hardest moments: the Delay Technique, Urge Surfing, replacement rituals, slip recovery, social pressure scripts, and the identity shift that makes quitting permanent.","Phase 2 is when withdrawal is often at its most intense: especially Days 8 to 10. Expect it. It passes. The tools in this phase are specifically designed for these days.","If symptoms become severe: particularly for alcohol reduction: contact 1800-11-2356 or a doctor immediately."],"highlight":"If symptoms become severe: particularly for alcohol reduction: contact 1800-11-2356 or a doctor immediately."},{"type":"close","message":"Day 7 is complete.","secondaryMessage":"Your quit is built one honest day at a time."}]'::jsonb
)
