INSERT INTO public.program_days (program_id, program_slug, day_number, day_title, title, estimated_minutes, cards)
VALUES (
  (SELECT id FROM public.programs WHERE slug = 'smoking_alcohol_quit' LIMIT 1),
  'smoking_alcohol_quit',
  8,
  'The Delay Technique',
  'Day 8 - The Delay Technique',
  19,
  '[{"type":"intro","dayNumber":8,"dayTitle":"The Delay Technique","goal":"The most evidence-backed single tool for managing urges","estimatedMinutes":19,"phase":"Phase 2 · Act"},{"type":"lesson","title":"What today is about","paragraphs":["The Delay Technique is the single most consistently effective tool in addiction research. It works because every urge has a peak: and the peak always falls if you do not feed it. You do not need to be strong. You only need to outlast 5 minutes for smoking or 15 minutes for alcohol."]},{"type":"audio","title":"Guided Audio","description":"Listen whenever you are ready for today’s guided reflection.","audioStoragePath":"ninety_day_transform/day-8.mp3","durationSeconds":420},{"type":"action_step","stepNumber":1,"title":"The Delay Technique: exact steps","instructions":["When the urge appears: say to yourself: \"I will wait 5 minutes before deciding.\" Not \"I will not smoke.\" Just \"I will wait 5 minutes.\"","During the 5 minutes for smoking / 15 minutes for alcohol: do ONE of these: Drink a full glass of cold water slowly. Or walk 50 steps anywhere. Or do 5 slow deep breaths (in for 4 counts, out for 6 counts).","When the time is up: check the urge. In 90% of cases it has dropped significantly. If it is still strong, do another 5 minutes.","After the delay: you can still choose to use. But most people do not. The delay breaks the automatic loop between trigger and action.","Repeat every time an urge appears today. You are building a new automatic response."],"whyThisWorks":"This turns the quit from willpower into a specific repeatable response."},{"type":"lesson","title":"Why this works","paragraphs":["Every nicotine craving peaks at 3 to 5 minutes and then drops neurologically: whether you act on it or not.","Every alcohol craving peaks at 15 to 20 minutes. The same neurological drop happens.","The automatic brain (habit brain) operates on less than a second of delay. A deliberate 5-minute delay activates the prefrontal cortex: the decision-making brain.","Research shows the Delay Technique alone reduces cigarette consumption by 30% in the first week.","Cold water is the most effective single action during the delay: it activates the parasympathetic nervous system and physically reduces craving intensity","Tell yourself \"I can have one in 5 minutes if I still want it\": this removes the panic of \"never again\" and makes the delay feel possible.","Open today’s card when an urge appears and repeat the delay steps until the urge drops."],"highlight":"The delay breaks the automatic loop between trigger and action."},{"type":"journal","prompt":"How many times did I use the Delay Technique today? What happened to the urge during the delay?","helperText":"One sentence is enough. Or skip entirely."},{"type":"action_step","stepNumber":2,"title":"If you slipped today","instructions":["One slip is not a relapse. One cigarette or one drink does not erase the work you have done."],"whyThisWorks":"A fast, non-shaming response prevents one slip from becoming a relapse loop."},{"type":"action_step","stepNumber":3,"title":"Do this in the next 60 minutes:","instructions":["Drink a full glass of cold water","Step outside or change the room you are in","Open today’s card and follow the 5-minute delay steps","Write one sentence: what happened just before?","Then continue the program from tomorrow. Nothing resets. You are still in this."],"whyThisWorks":"A fast, non-shaming response prevents one slip from becoming a relapse loop."},{"type":"close","message":"Day 8 is complete.","secondaryMessage":"Your quit is built one honest day at a time."}]'::jsonb
)
