INSERT INTO public.program_days (program_id, program_slug, day_number, day_title, title, estimated_minutes, cards)
VALUES (
  (SELECT id FROM public.programs WHERE slug = 'smoking_alcohol_quit' LIMIT 1),
  'smoking_alcohol_quit',
  11,
  'Social Pressure',
  'Day 11 - Social Pressure',
  19,
  '[{"type":"intro","dayNumber":11,"dayTitle":"Social Pressure","goal":"Handle the people and situations that make quitting hardest","estimatedMinutes":19,"phase":"Phase 2 · Act"},{"type":"lesson","title":"What today is about","paragraphs":["More than 40% of relapses happen in social situations: not because the person lacks commitment but because they did not have a prepared, rehearsed response. Today you prepare one."]},{"type":"audio","title":"Guided Audio","description":"Listen whenever you are ready for today’s guided reflection.","audioStoragePath":"ninety_day_transform/day-11.mp3","durationSeconds":420},{"type":"lesson","title":"\"Just one won''t hurt.\"","paragraphs":["Response: \"I''m good, thanks.\": nothing more. Offering a reason invites debate. A calm, brief response ends the conversation."]},{"type":"lesson","title":"\"Come on, it''s a celebration.\"","paragraphs":["Response: \"I''m celebrating with you: just without the drink tonight.\" Hold a glass of lime soda or water. Nobody can tell the difference from across the room."]},{"type":"lesson","title":"\"You used to be fun.\"","paragraphs":["Response: \"I''m having fun. I just don''t need a cigarette/drink to prove it.\" Calm. Not defensive. If they push further, change the subject. This is their discomfort with your change, not a genuine comment about you."]},{"type":"lesson","title":"\"I''ll join you for just one.\"","paragraphs":["Response: \"Go ahead. I''ll be here.\" You do not need to explain your quit to everyone. Simply not participating is enough."]},{"type":"lesson","title":"The preparation rule","paragraphs":["Before any social situation where smoking or drinking will be present, spend 60 seconds mentally rehearsing:","What is my response if offered a cigarette or drink?","What will I hold in my hand? (Water, lime soda, juice: always have something)","What is my exit if the pressure becomes too much?","You do not owe anyone an explanation for quitting. \"I''m good thanks\" is a complete sentence.","Holding a non-alcoholic drink removes 80% of social pressure immediately: most people are watching the glass, not you","Tell your closest friends before the event so you have at least one ally in the room","It is completely acceptable to leave early from situations that feel too difficult this week"],"highlight":"It is completely acceptable to leave early from situations that feel too difficult this week"},{"type":"journal","prompt":"Was there a social situation that challenged me today? What did I say or do? What would I do differently?","helperText":"One sentence is enough. Or skip entirely."},{"type":"action_step","stepNumber":1,"title":"If you slipped today","instructions":["One slip is not a relapse. One cigarette or one drink does not erase the work you have done."],"whyThisWorks":"A fast, non-shaming response prevents one slip from becoming a relapse loop."},{"type":"action_step","stepNumber":2,"title":"Do this in the next 60 minutes:","instructions":["Drink a full glass of cold water","Step outside or change the room you are in","Open today’s card and follow the 5-minute delay steps","Write one sentence: what happened just before?","Then continue the program from tomorrow. Nothing resets. You are still in this."],"whyThisWorks":"A fast, non-shaming response prevents one slip from becoming a relapse loop."},{"type":"close","message":"Day 11 is complete.","secondaryMessage":"Your quit is built one honest day at a time."}]'::jsonb
)
