INSERT INTO public.program_days (program_id, program_slug, day_number, day_title, title, estimated_minutes, cards)
VALUES (
  (SELECT id FROM public.programs WHERE slug = 'smoking_alcohol_quit' LIMIT 1),
  'smoking_alcohol_quit',
  12,
  'When You Slip',
  'Day 12 - When You Slip',
  19,
  '[{"type":"intro","dayNumber":12,"dayTitle":"When You Slip","goal":"The exact recovery protocol for when things do not go to plan","estimatedMinutes":19,"phase":"Phase 2 · Act"},{"type":"lesson","title":"What today is about","paragraphs":["This day comes before a slip happens: so you are already prepared if it does. Research shows that how someone responds to a slip determines more about long-term quitting success than whether the slip happened at all.","The most dangerous moment in any quit attempt is not the slip. It is the 60 minutes after the slip: when all-or-nothing thinking says \"I have already ruined it, I might as well continue.\" This is the thinking that turns one cigarette into a full relapse."],"highlight":"The most dangerous moment in any quit attempt is not the slip. It is the 60 minutes after the slip: when all-or-nothing thinking says \"I have already ruined it, I might as well continue.\" This is the thinking that turns one cigarette into a full relapse."},{"type":"audio","title":"Guided Audio","description":"Listen whenever you are ready for today’s guided reflection.","audioStoragePath":"ninety_day_transform/day-12.mp3","durationSeconds":420},{"type":"lesson","title":"One cigarette is not a relapse. One drink is not a relapse.","paragraphs":["A relapse is a return to the full habit over multiple days. A slip is a single event. They are not the same thing.","Research on successful quitters: 85% of people who quit permanently had at least one slip during their successful quit attempt. The slip did not end their quit. Their response to the slip determined everything."],"highlight":"Research on successful quitters: 85% of people who quit permanently had at least one slip during their successful quit attempt. The slip did not end their quit. Their response to the slip determined everything."},{"type":"action_step","stepNumber":1,"title":"The 60-minute slip recovery protocol","instructions":["The moment you realise you slipped: stop. Do not have another one. That is the only rule.","Drink a full glass of cold water immediately. This is physiological and it works.","Change your location: step outside, move to a different room, leave the building.","Open today’s card and follow the 5-minute delay steps.","Write one sentence: \"What happened just before the slip?\" Not judgement: information.","Return to the program tomorrow from exactly the day you are on. Nothing resets. Nothing is lost.","Do not tell yourself \"I have failed.\" Tell yourself \"I have data. I know what led to this. I continue.\""],"whyThisWorks":"This turns the quit from willpower into a specific repeatable response."},{"type":"lesson","title":"The internal response matters most","paragraphs":["After a slip, the brain produces shame. Shame produces the urge to escape. The familiar escape is the cigarette or drink. This is the relapse loop.","Breaking the loop requires one specific thought: \"This slip does not define the quit. My response right now defines the quit.\"","You have already built 11 days of tools and awareness. One slip does not erase that. The tools are still there. The decision is still there. Continuing is more important than the slip itself."],"highlight":"You have already built 11 days of tools and awareness. One slip does not erase that. The tools are still there. The decision is still there. Continuing is more important than the slip itself."},{"type":"journal","prompt":"If I slipped today: what happened just before? What does that tell me about my specific triggers?","helperText":"If I did not slip: what made today manageable? What do I want to remember for harder days?"},{"type":"close","message":"Day 12 is complete.","secondaryMessage":"Your quit is built one honest day at a time."}]'::jsonb
)
