INSERT INTO public.program_days (program_id, program_slug, day_number, day_title, title, estimated_minutes, cards)
VALUES (
  (SELECT id FROM public.programs WHERE slug = 'smoking_alcohol_quit' LIMIT 1),
  'smoking_alcohol_quit',
  16,
  'Handling Cravings in the Body',
  'Day 16 - Handling Cravings in the Body',
  19,
  '[{"type":"intro","dayNumber":16,"dayTitle":"Handling Cravings in the Body","goal":"Physical techniques that reduce craving intensity in real time","estimatedMinutes":19,"phase":"Phase 3 · Hold"},{"type":"lesson","title":"What today is about","paragraphs":["By Day 16, cravings are shorter and less frequent. But they still come: sometimes strongly and without warning. Today you build a personal toolkit of physical craving responses that work in the moment."]},{"type":"audio","title":"Guided Audio","description":"Listen whenever you are ready for today’s guided reflection.","audioStoragePath":"ninety_day_transform/day-16.mp3","durationSeconds":420},{"type":"action_step","stepNumber":1,"title":"The physical craving toolkit","instructions":["COLD WATER (fastest): drink a full glass of cold water immediately. Cold water activates the parasympathetic nervous system within 60 seconds and measurably reduces craving intensity. This is the single most consistently effective immediate tool.","4-6 BREATHING: inhale for 4 counts, exhale for 6 counts. Repeat 5 times. The long exhale drops cortisol. This is the same physiological mechanism as a cigarette: minus the nicotine. It genuinely works.","PHYSICAL MOVEMENT: 50 steps anywhere. 10 jumping jacks. Movement metabolises the cortisol and adrenaline that amplify cravings. Even 2 minutes of movement measurably shortens craving duration.","COLD WATER ON FACE: splash cold water on face for 10 seconds. Triggers the dive reflex: immediate drop in heart rate and craving intensity.","GRIP SOMETHING: hold a pen, stress ball, or cold glass. The hands are part of the smoking habit loop. Giving them something to do breaks the automatic reach.","THE 5-MINUTE RULE: tell yourself \"I will wait 5 more minutes.\" Set a phone timer. When it ends, most cravings have already dropped."],"whyThisWorks":"This turns the quit from willpower into a specific repeatable response."},{"type":"action_step","stepNumber":2,"title":"Choose your primary and backup tool","instructions":["You cannot decide which tool to use when the craving is peak: the brain defaults to the habit. Decide now:","My PRIMARY tool (the first thing I will do when a craving hits):","My BACKUP tool (if the primary is not possible):"],"whyThisWorks":"This turns the quit from willpower into a specific repeatable response."},{"type":"journal","prompt":"Which physical tool worked best today and why? What does the craving feel like now compared to Day 8?","helperText":"One sentence is enough. Or skip entirely."},{"type":"action_step","stepNumber":3,"title":"If you slipped today","instructions":["One slip is not a relapse. One cigarette or one drink does not erase the work you have done."],"whyThisWorks":"A fast, non-shaming response prevents one slip from becoming a relapse loop."},{"type":"action_step","stepNumber":4,"title":"Do this in the next 60 minutes:","instructions":["Drink a full glass of cold water","Step outside or change the room you are in","Open today’s card and follow the 5-minute delay steps","Write one sentence: what happened just before?","Then continue the program from tomorrow. Nothing resets. You are still in this."],"whyThisWorks":"A fast, non-shaming response prevents one slip from becoming a relapse loop."},{"type":"close","message":"Day 16 is complete.","secondaryMessage":"Your quit is built one honest day at a time."}]'::jsonb
)
