INSERT INTO public.program_days (program_id, program_slug, day_number, day_title, title, estimated_minutes, cards)
VALUES (
  (SELECT id FROM public.programs WHERE slug = 'smoking_alcohol_quit' LIMIT 1),
  'smoking_alcohol_quit',
  17,
  'The Identity Shift',
  'Day 17 - The Identity Shift',
  19,
  '[{"type":"intro","dayNumber":17,"dayTitle":"The Identity Shift","goal":"The most powerful quit tool: becoming someone who does not smoke or drink","estimatedMinutes":19,"phase":"Phase 3 · Hold"},{"type":"lesson","title":"What today is about","paragraphs":["There is a fundamental difference between two types of quitters:","Type 1 says: \"I am trying to quit smoking.\": This person is resisting a cigarette. Every urge is a battle. The identity is still that of a smoker trying not to smoke.","Type 2 says: \"I am not a smoker.\": This person is not resisting anything. When offered a cigarette they say \"No thanks, I don''t smoke.\" Full stop.","Research by James Clear and others shows that identity-based quitting produces dramatically better long-term outcomes than willpower-based quitting. Today you begin the identity shift."],"highlight":"Research by James Clear and others shows that identity-based quitting produces dramatically better long-term outcomes than willpower-based quitting. Today you begin the identity shift."},{"type":"audio","title":"Guided Audio","description":"Listen whenever you are ready for today’s guided reflection.","audioStoragePath":"ninety_day_transform/day-17.mp3","durationSeconds":420},{"type":"action_step","stepNumber":1,"title":"The identity shift in practice","instructions":["The shift does not happen all at once. It is built through small daily evidence. Every time you handle a craving with a tool instead of the substance, you cast a vote for the new identity."],"whyThisWorks":"This turns the quit from willpower into a specific repeatable response."},{"type":"lesson","title":"Starting today, change how you speak about your quit:","paragraphs":["Instead of: \"I am trying to quit smoking\" → say: \"I don''t smoke\"","Instead of: \"I am trying not to drink\" → say: \"I don''t drink\"","Instead of: \"I can''t have one\" → say: \"I don''t want one\"","The language is not a lie. It is the identity you are building. The more you say it, the more the brain believes it. The more the brain believes it, the less the habit is part of you."],"highlight":"The language is not a lie. It is the identity you are building. The more you say it, the more the brain believes it. The more the brain believes it, the less the habit is part of you."},{"type":"action_step","stepNumber":2,"title":"Complete this statement and write it somewhere you will see it:","instructions":["\"I am someone who _____. I handle stress by _____. I socialise without needing _____. I wake up without the first thought being _____.\""],"whyThisWorks":"This turns the quit from willpower into a specific repeatable response."},{"type":"journal","prompt":"What does it mean to be someone who does not smoke or drink? Who is that person and how do they live?","helperText":"Write freely. This is not about perfection: it is about direction."},{"type":"action_step","stepNumber":3,"title":"If you slipped today","instructions":["One slip is not a relapse. One cigarette or one drink does not erase the work you have done."],"whyThisWorks":"A fast, non-shaming response prevents one slip from becoming a relapse loop."},{"type":"action_step","stepNumber":4,"title":"Do this in the next 60 minutes:","instructions":["Drink a full glass of cold water","Step outside or change the room you are in","Open today’s card and follow the 5-minute delay steps","Write one sentence: what happened just before?","Then continue the program from tomorrow. Nothing resets. You are still in this."],"whyThisWorks":"A fast, non-shaming response prevents one slip from becoming a relapse loop."},{"type":"close","message":"Day 17 is complete.","secondaryMessage":"Your quit is built one honest day at a time."}]'::jsonb
)
