INSERT INTO public.program_days (program_id, program_slug, day_number, day_title, title, estimated_minutes, cards)
VALUES (
  (SELECT id FROM public.programs WHERE slug = 'smoking_alcohol_quit' LIMIT 1),
  'smoking_alcohol_quit',
  21,
  'You Are Different Now',
  'Day 21 - You Are Different Now',
  19,
  '[{"type":"intro","dayNumber":21,"dayTitle":"You Are Different Now","goal":"Close the program. Carry the quit.","estimatedMinutes":19,"phase":"Phase 3 · Hold"},{"type":"lesson","title":"What today is about","paragraphs":["Today is not a graduation. It is not a finish line. It is the point where the program hands the quit back to you: because you are now the person who knows how to carry it."]},{"type":"audio","title":"Guided Audio","description":"Listen whenever you are ready for today’s guided reflection.","audioStoragePath":"ninety_day_transform/day-21.mp3","durationSeconds":420},{"type":"lesson","title":"What you have built in 21 days","paragraphs":["You began with honesty about why you use and what it costs.","You mapped your triggers with specificity that most people never build in a lifetime.","You understood the emotional job the habit was doing: and found better tools to do it.","You learned the Delay Technique and Urge Surfing: two clinically proven tools that will work for you indefinitely. You built specific plans for the morning, after meals, stress, and social pressure.","You read the slip recovery protocol before you needed it: so a slip, if it comes, does not become a relapse. You watched your body heal and made the gains specific and real.","You shifted from \"trying to quit\" to \"I don''t smoke/drink.\"","You built a post-program plan for the 90 days that follow."],"highlight":"You built a post-program plan for the 90 days that follow."},{"type":"lesson","title":"Answer these five questions: honestly, without judgment:","paragraphs":["What is the most important thing I understand now that I did not understand on Day 1?","What is the tool I will never stop using?","What does the version of me who stays quit look like in one year?","What do I want to tell myself on a day, in week 8, when it is difficult again?","What am I most proud of from these 21 days?"],"highlight":"What am I most proud of from these 21 days?"},{"type":"lesson","title":"The honest close","paragraphs":["This program gave you tools. It cannot give you the quit. That was always yours to carry.","Some days after Day 21 will be hard. The tools will feel distant. The urge will feel strong. On those days: come back to Day 8. Use the Delay Technique. Ride the wave. Call your supporter. Call the Quitline. Use the slip protocol if you need it.","You are not on your own. The tools do not expire. The support lines are still open. The program is still here."],"highlight":"You are not on your own. The tools do not expire. The support lines are still open. The program is still here."},{"type":"action_step","stepNumber":1,"title":"Emergency Support Lines: Save These Now","instructions":["Quitline: 1800-11-2356 (free, confidential) · iCall: 9152987821 · KIRAN Mental Health: 1800-599-0019"],"whyThisWorks":"This turns the quit from willpower into a specific repeatable response."},{"type":"journal","prompt":"My final reflection: what I understand now, what I carry forward, and what I want to remember on a hard day.","helperText":"Write this carefully. You may return to it."},{"type":"close","message":"You completed the 21-day quit program.","secondaryMessage":"The tools do not expire. Keep using them after the program ends."}]'::jsonb
)
